// Deduplicate templates that share identical interval sets (keep first occurrence)
// This prevents the same chord combo from matching multiple template names.
const _seenIntervalSigs = new Set();
const CHORD_TEMPLATES_DEDUPED = CHORD_TEMPLATES.filter(t => {
  if (t.octave) return true; // octave is special-cased anyway
  const sig = t.intervals.slice().sort((a,b)=>a-b).join(",");
  if (_seenIntervalSigs.has(sig)) return false;
  _seenIntervalSigs.add(sig);
  return true;
});
// Replace the original reference
const TEMPLATES_FINAL = CHORD_TEMPLATES_DEDUPED;

