const NOTE_COLOR_MAP={
  "C3":"#e8c97a","C4":"#e8c97a","D4":"#7ec8a0",
  "Eb4":"#88aaee","F4":"#e88888","G4":"#c0a0e0",
  "Ab4":"#f0b870","C5":"#e8d4a0","D5":"#8ecfa8",
};
// Palette by semitone for unknown notes — guarantees every note has a color
const SEMITONE_PALETTE=[
  "#e8c97a","#d4a8d0","#7ec8a0","#88aaee","#e8a870","#e88888",
  "#c8e870","#c0a0e0","#f0b870","#70c8c8","#aad4a8","#d0c0e0",
];
function NOTE_COLOR(name){
  if(NOTE_COLOR_MAP[name]) return NOTE_COLOR_MAP[name];
  // derive from pitch class
  const semi = SEMITONE_NAMES.indexOf(name.replace(/\d/,""));
  return SEMITONE_PALETTE[semi>=0?semi:0];
}

// ═══════════════════════════════════════════════════════════════════
// AUDIO ENGINE — real handpan samples + pitch shifting
//
// What the samples revealed:
//  • 2f (octave) is AS LOUD or LOUDER than the fundamental (+1 dB on G3/G4)
//  • 3f (compound 5th) beats at ~2–4 Hz with full depth (goes to near zero)
//  • The octave itself also beats, slower on lower notes (~2.6 Hz on G4)
//  • Decay: 2f hits -20dB in ~0.4–0.7s (much faster than our old model)
//  • Attack: 5–25ms to peak
//
// Strategy: use 4 recorded samples pitched via playbackRate, then add
// the beat/wave tremolo on top with an AM oscillator layer.
// ═══════════════════════════════════════════════════════════════════
let _audioCtx = null;
let _limiter  = null;
let _outGain  = null;
let _buffers  = {};   // decoded AudioBuffer cache
let _loadingPromises = {};

// ── Embedded samples (16kHz mono WAV, base64) ─────────────────────
const SAMPLE_DEFS = {
  "G3": { freq: 196.0, b64: `` },
  "C4": { freq: 261.63, b64: `` },
  "G4": { freq: 392.0, b64: `` },
  "C5": { freq: 523.25, b64: `` },
};

function getCtx() {
  if (!_audioCtx || _audioCtx.state === "closed") {
    _audioCtx = new (window.AudioContext || window.webkitAudioContext)();
    _limiter = _audioCtx.createDynamicsCompressor();
    _limiter.threshold.value = -8;
    _limiter.knee.value      = 3;
    _limiter.ratio.value     = 14;
    _limiter.attack.value    = 0.001;
    _limiter.release.value   = 0.12;
    _outGain = _audioCtx.createGain();
    _outGain.gain.value = 0.78;
    _outGain.connect(_limiter);
    _limiter.connect(_audioCtx.destination);
    // Pre-load all buffers
    Object.keys(SAMPLE_DEFS).forEach(loadBuffer);
  }
  if (_audioCtx.state === "suspended") _audioCtx.resume();
  return _audioCtx;
}

function b64ToArrayBuffer(b64) {
  const bin = atob(b64);
  const buf = new ArrayBuffer(bin.length);
  const view = new Uint8Array(buf);
  for (let i = 0; i < bin.length; i++) view[i] = bin.charCodeAt(i);
  return buf;
}

function loadBuffer(key) {
  if (_buffers[key]) return Promise.resolve(_buffers[key]);
  if (_loadingPromises[key]) return _loadingPromises[key];
  const ctx = _audioCtx;
  _loadingPromises[key] = ctx.decodeAudioData(b64ToArrayBuffer(SAMPLE_DEFS[key].b64))
    .then(buf => { _buffers[key] = buf; return buf; })
    .catch(err => { console.warn("Sample load failed:", key, err); return null; });
  return _loadingPromises[key];
}

// Pick closest sample key by pitch
function closestSample(freq) {
  const keys = Object.keys(SAMPLE_DEFS);
  let best = keys[0], bestDist = Infinity;
  for (const k of keys) {
    const d = Math.abs(Math.log2(freq / SAMPLE_DEFS[k].freq));
    if (d < bestDist) { bestDist = d; best = k; }
  }
  return best;
}

// ── Play one note using the real sample ──────────────────────────
async function playNoteAsync(freq, t, ctx, vol) {
  const sampleKey = closestSample(freq);
  const buf = _buffers[sampleKey] || await loadBuffer(sampleKey);
  if (!buf) return;

  const freqNorm = Math.log2(freq / 130);  // 0 at C3 → ~2.17 at D5

  // ── Sample playback ──────────────────────────────────────────
  const src = ctx.createBufferSource();
  src.buffer = buf;
  src.playbackRate.value = freq / SAMPLE_DEFS[sampleKey].freq;

  const sampGain = ctx.createGain();
  sampGain.gain.setValueAtTime(vol * 0.92, t);

  src.connect(sampGain);
  sampGain.connect(_outGain);
  src.start(t);
  // Stop after ~6s (sample is only 4s, will naturally end anyway)
  src.stop(t + 6);

  // ── Beat/wave tremolo layer ────────────────────────────────────
  // From the samples: the octave partial beats at ~2.6–5 Hz.
  // Lower notes have slower, deeper beats. We add an AM oscillator
  // that modulates the sample volume to recreate this.
  //
  // Beat rate: measured ~0.4 Hz at G3 rising to ~8 Hz at C5
  // We use: beatHz = 0.5 + freqNorm * 3.0
  // Depth: 80% modulation on low notes, 30% on high
  const beatHz   = Math.min(0.5 + freqNorm * 3.0, 7.5);
  const depth    = Math.max(0.25, 0.82 - freqNorm * 0.25);  // 0.82→0.25
  const minLevel = 1 - depth;  // how low the trough goes (0.18→0.75)

  // AM: gain oscillates between minLevel and 1.0
  // output = (1+minLevel)/2 + sin*(1-minLevel)/2
  const amLFO = ctx.createOscillator();
  const amMix = ctx.createGain();
  const amDC  = ctx.createConstantSource();
  const amOut = ctx.createGain();

  amLFO.type = "sine";
  amLFO.frequency.value = beatHz;
  amMix.gain.value  = (1 - minLevel) / 2;
  amDC.offset.value = (1 + minLevel) / 2;
  amOut.gain.value  = 1;

  amLFO.connect(amMix); amMix.connect(amOut);
  amDC.connect(amOut);

  // The AM modulates the sample's output gain
  const tremoloGain = ctx.createGain();
  tremoloGain.gain.setValueAtTime(0, t);   // driven by amOut
  sampGain.disconnect(_outGain);
  sampGain.connect(tremoloGain);
  amOut.connect(tremoloGain.gain);         // AM modulation
  tremoloGain.connect(_outGain);

  const dur = 5.5;
  amLFO.start(t); amLFO.stop(t + dur);
  amDC.start(t);  amDC.stop(t + dur);
}

function synthNote(freq, t, ctx, vol) {
  // Fire and forget — load sample if not ready
  const sampleKey = closestSample(freq);
  if (_buffers[sampleKey]) {
    // Buffer ready — play synchronously via internal async (but buffer already loaded)
    playNoteAsync(freq, t, ctx, vol);
  } else {
    // Buffer not yet loaded — schedule via promise
    loadBuffer(sampleKey).then(() => {
      if (ctx.state !== "closed") playNoteAsync(freq, ctx.currentTime + 0.05, ctx, vol);
    });
  }
}

function playNote(name) {
  const f = HANDPAN.freq[name]; if (!f) return;
  const ctx = getCtx(); synthNote(f, ctx.currentTime, ctx, 0.80);
}

function playChord(notes, stagger = 0.07, freqMap) {
  const ctx = getCtx(), now = ctx.currentTime;
  const noteVol = Math.max(0.45, 0.80 - notes.length * 0.06);
  notes.forEach((n, i) => {
    const f = (freqMap||HANDPAN.freq)[n];
    if (f) synthNote(f, now + i * stagger, ctx, noteVol);
  });
}


// ═══════════════════════════════════════════════════════════════════
// HANDPAN SVG DIAGRAM
// ═══════════════════════════════════════════════════════════════════
function HandpanDiagram({ activeNotes, onNoteToggle, notePositions, panNotes, uniqueId="hp" }) {
  const CX=150, CY=150, RING_R=90;
  const noteList = panNotes || HANDPAN.notes;

  function getNotePos(noteName) {
    if (notePositions && notePositions[noteName] !== undefined) {
      const pos = notePositions[noteName];
      // New format: "angle:ringIdx:side" | "ding:0:upper" | legacy "angle:ringIdx" | "ding"
      if (pos === "ding" || pos === "big-ding" || pos === "small-ding")
        return { x:CX, y:CY, r:36, isDing:true };
      const parts = String(pos).split(":");
      if(parts[0]==="ding") return { x:CX, y:CY, r:36, isDing:true };
      const deg = parseFloat(parts[0])||0;
      const ri  = parseInt(parts[1]||0);
      const rr  = [RING_R, RING_R*0.69, RING_R*0.44][Math.min(ri,2)];
      const rad = ((deg-90)*Math.PI)/180;
      return { x:+(CX+rr*Math.cos(rad)).toFixed(2), y:+(CY+rr*Math.sin(rad)).toFixed(2), r:24, isDing:false };
    }
    return NOTE_POS[noteName] || null;
  }

  // Render ALL passed notes — caller decides upper vs bottom split
  // ding notes last so they render on top
  const renderList = [
    ...noteList.filter(n=>!getNotePos(n.name)?.isDing),
    ...noteList.filter(n=>getNotePos(n.name)?.isDing),
  ];
  return (
    <svg width="100%" viewBox="0 0 300 300" style={{display:"block",maxWidth:260,margin:"0 auto",touchAction:"none",userSelect:"none",WebkitUserSelect:"none",WebkitTapHighlightColor:"transparent"}}>
      <defs>
        <radialGradient id={`hpBody_${uniqueId}`} cx="50%" cy="50%" r="55%" gradientUnits="objectBoundingBox">
          <stop offset="0%"   stopColor="#5c4e28"/>
          <stop offset="28%"  stopColor="#3a3018"/>
          <stop offset="60%"  stopColor="#1e1a0c"/>
          <stop offset="100%" stopColor="#080705"/>
        </radialGradient>
        <radialGradient id={`hpSheen_${uniqueId}`} cx="38%" cy="32%" r="48%">
          <stop offset="0%"  stopColor="rgba(255,230,140,0.22)"/>
          <stop offset="60%" stopColor="rgba(255,210,100,0.06)"/>
          <stop offset="100%"stopColor="rgba(255,200,80,0.00)"/>
        </radialGradient>
        <filter id={`hpGlow_${uniqueId}`} x="-60%" y="-60%" width="220%" height="220%">
          <feGaussianBlur stdDeviation="5" result="b"/>
          <feMerge><feMergeNode in="b"/><feMergeNode in="SourceGraphic"/></feMerge>
        </filter>
      </defs>

      {/* Rim layers */}
      <circle cx={CX} cy={CY} r={146} fill="rgba(0,0,0,0.55)"/>
      <circle cx={CX} cy={CY} r={143} fill="none" stroke="rgba(160,120,40,0.30)" strokeWidth={1.5}/>
      <circle cx={CX} cy={CY} r={141} fill={`url(#hpBody_${uniqueId})`} stroke="rgba(200,155,55,0.50)" strokeWidth={2}/>
      <circle cx={CX} cy={CY} r={138} fill="none" stroke="rgba(240,195,80,0.18)" strokeWidth={1}/>
      <circle cx={CX} cy={CY} r={141} fill={`url(#hpSheen_${uniqueId})`}/>
      <circle cx={CX} cy={CY} r={115} fill="none" stroke="rgba(205,163,83,0.10)" strokeWidth={1} strokeDasharray="4 8"/>
      <circle cx={CX} cy={CY} r={50}  fill="none" stroke="rgba(205,163,83,0.08)" strokeWidth={1}/>

      {/* Spokes */}
      {renderList.filter(n=>!getNotePos(n.name)?.isDing).map(n=>{
        const p=getNotePos(n.name);
        if(!p) return null;
        const lit=activeNotes.includes(n.name);
        return <line key={n.name} x1={CX} y1={CY} x2={p.x} y2={p.y}
          stroke={lit?(NOTE_COLOR(n.name))+"66":"rgba(205,163,83,0.06)"}
          strokeWidth={lit?1.5:.8} style={{transition:"stroke .25s"}}/>;
      })}

      {/* Tone fields — ding last */}
      {renderList.map(n=>{
        const pos=getNotePos(n.name);
        if(!pos) return null;
        const {x,y,isDing}=pos;
        // Use note's actual size definition for radius and fonts
        const sizeDef = NOTE_SIZES[n.size||"medium"] || (isDing ? NOTE_SIZES["big-ding"] : NOTE_SIZES["medium"]);
        const r = sizeDef.r;
        const lit=activeNotes.includes(n.name), col=NOTE_COLOR(n.name);
        const lbl=n.name.replace("b","♭").replace(/\d/,"");
        const oct=n.name.match(/\d/)?.[0]||"";
        return (
          <g key={n.name} onClick={()=>onNoteToggle(n.name)} style={{cursor:"pointer"}}>
            {lit&&<circle cx={x} cy={y} r={r+13} fill={col+"18"} filter={`url(#hpGlow_${uniqueId})`}/>}
            <circle cx={x} cy={y} r={r+2} fill="none"
              stroke={lit?col+"55":"rgba(180,140,55,0.15)"}
              strokeWidth={lit?1.5:1} style={{transition:"stroke .2s"}}/>
            <circle cx={x} cy={y} r={r}
              fill={lit?col+"38":isDing?"rgba(205,163,83,0.12)":"rgba(20,17,8,0.88)"}
              stroke={lit?col:isDing?"rgba(205,163,83,0.60)":"rgba(140,110,45,0.25)"}
              strokeWidth={lit?2.5:1.5} style={{transition:"all .2s"}}/>
            <circle cx={x} cy={y} r={Math.max(r-6,4)} fill="none"
              stroke={lit?col+"44":"rgba(205,163,83,0.06)"}
              strokeWidth={.8} style={{transition:"stroke .2s"}}/>
            <text x={x} y={isDing?y-(r>30?5:4):y+1}
              textAnchor="middle" dominantBaseline="middle"
              fontSize={sizeDef.fontSize} fontFamily={FONT} fontWeight="600"
              fill={lit?col:isDing?"#d4a830":"#9a8a60"}
              style={{userSelect:"none",pointerEvents:"none",transition:"fill .2s"}}>{lbl}</text>
            {oct&&<text x={x} y={isDing?y+(r>30?9:7):y+r*0.55}
              textAnchor="middle" fontSize={sizeDef.subFontSize} fontFamily={FONT} fontWeight="600"
              fill={lit?col+(isDing?"cc":"99"):isDing?"#8a7040":"#7a6840"}
              style={{userSelect:"none",pointerEvents:"none"}}>{oct}</text>}
            {isDing&&<text x={x} y={y+(oct?r*0.75:r*0.5)}
              textAnchor="middle" fontSize={sizeDef.subFontSize-1} fontFamily={FONT} fontWeight="500"
              fill={lit?col+"ee":"#8a7040"}
              style={{userSelect:"none",pointerEvents:"none"}}>ding</text>}
          </g>
        );
      })}
    </svg>
  );
}

// ═══════════════════════════════════════════════════════════════════
// FILTER MODAL
// ═══════════════════════════════════════════════════════════════════
const NOTE_LIST = HANDPAN.notes.map(n=>n.name);

function FilterModal({open,onClose,filters,onChange,availableCats,availableChordNames,noteList}) {
  const [visible,setVisible]=useState(false);
  const [animIn, setAnimIn] =useState(false);
  const [dragY,   setDragY]   = useState(0);
  const dragging  = useRef(false);
  const dragStart = useRef(null);
  const panelRef  = useRef(null);

  useEffect(()=>{
    if(open){
      setDragY(0);
      setVisible(true);
      requestAnimationFrame(()=>requestAnimationFrame(()=>setAnimIn(true)));
    } else {
      setAnimIn(false);
      const t=setTimeout(()=>setVisible(false),320);
      return()=>clearTimeout(t);
    }
  },[open]);
  if(!visible) return null;

  const DISMISS_THRESHOLD = 90;

  const startDrag = (y) => {
    // Only allow drag from top of scroll content
    if (panelRef.current && panelRef.current.scrollTop > 2) return;
    dragStart.current = y;
    dragging.current  = true;
  };
  const moveDrag = (y) => {
    if (!dragging.current || dragStart.current === null) return;
    setDragY(Math.max(0, y - dragStart.current));
  };
  const endDrag = (y) => {
    if (!dragging.current) return;
    dragging.current = false;
    const dy = Math.max(0, y - (dragStart.current ?? y));
    dragStart.current = null;
    if (dy >= DISMISS_THRESHOLD) { setDragY(0); onClose(); }
    else setDragY(0);
  };

  const {noteCounts, cats, notes, chordNames} = filters;

  // Toggle an array filter: clicking adds if absent, removes if present
  const toggle = (key, val) => {
    const arr = filters[key];
    const next = arr.includes(val) ? arr.filter(v => v !== val) : [...arr, val];
    onChange({...filters, [key]: next});
  };

  const Chip=({active,color,onClick,children})=>(
    <button onClick={onClick} style={{
      background:active?(color?color+"28":"rgba(205,163,83,0.20)"):"rgba(255,255,255,0.04)",
      border:`1px solid ${active?(color||"rgba(205,163,83,0.60)"):"rgba(255,255,255,0.08)"}`,
      color:active?(color||"#e8d4a0"):"#6a5840",
      borderRadius:6,padding:"5px 11px",cursor:"pointer",
      fontSize:11,fontFamily:FONT,fontWeight:"400",
      transition:"all .13s",whiteSpace:"nowrap",
    }}>{children}</button>
  );
  const Label=({children})=>(
    <div style={{fontSize:9,letterSpacing:3,color:"#7a6030",textTransform:"uppercase",
      marginBottom:7,fontFamily:FONT,fontWeight:"600"}}>{children}</div>
  );

  return (
    <>
      <div onClick={onClose} style={{
        position:"fixed",inset:0,zIndex:200,background:"rgba(0,0,0,0.55)",
        backdropFilter:"blur(3px)",opacity:animIn?1:0,transition:"opacity .3s ease",
      }}/>
      <div
        ref={panelRef}
        onMouseDown={e=>startDrag(e.clientY)}
        onMouseMove={e=>moveDrag(e.clientY)}
        onMouseUp={e=>endDrag(e.clientY)}
        onMouseLeave={e=>endDrag(e.clientY)}
        onTouchStart={e=>startDrag(e.touches[0].clientY)}
        onTouchMove={e=>{e.preventDefault();moveDrag(e.touches[0].clientY);}}
        onTouchEnd={e=>endDrag(e.changedTouches[0].clientY)}
        style={{
          position:"fixed",bottom:0,left:0,right:0,zIndex:201,
          background:"#181208",borderTop:"1px solid rgba(205,163,83,0.22)",
          borderRadius:"18px 18px 0 0",
          maxHeight:"82vh",overflowY:"auto",fontFamily:FONT,
          transform: dragY > 0
            ? `translateY(${dragY}px)`
            : animIn ? "translateY(0)" : "translateY(100%)",
          transition: dragY > 0 ? "none" : "transform .32s cubic-bezier(.32,.72,.00,1.00)",
          boxShadow:"0 -12px 48px rgba(0,0,0,0.6)",
          userSelect:"none",
          touchAction:"pan-x",
        }}>
        {/* Centred content wrapper — same max-width as the rest of the page */}
        <div style={{maxWidth:880,margin:"0 auto",padding:"20px 18px 36px"}}>
        <div style={{width:40,height:4,background:"rgba(205,163,83,0.20)",borderRadius:2,margin:"0 auto 18px"}}/>
        <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:18}}>
          <div style={{fontSize:16,color:"#d4c090",letterSpacing:.5,fontFamily:FONT,fontWeight:"700"}}>Filters</div>
          <button onClick={onClose} style={{background:"none",border:"none",color:"#6a5830",fontSize:18,cursor:"pointer",lineHeight:1,padding:"4px 8px"}}>✕</button>
        </div>

        <Label>Note count</Label>
        <div style={{display:"flex",gap:6,flexWrap:"wrap",marginBottom:18}}>
          {["all","2","3","4","5"].map(n=>(
            <Chip key={n}
              active={n==="all" ? noteCounts.length===0 : noteCounts.includes(parseInt(n))}
              onClick={()=> n==="all" ? onChange({...filters, noteCounts:[]}) : toggle("noteCounts", parseInt(n))}>
              {n==="all"?"All":`${n} notes`}
            </Chip>
          ))}
        </div>

        <Label>Category</Label>
        <div style={{display:"flex",gap:6,flexWrap:"wrap",marginBottom:18}}>
          {["all",...(availableCats||CAT_ORDER)].map(c=>(
            <Chip key={c}
              active={c==="all" ? cats.length===0 : cats.includes(c)}
              color={c!=="all"?CAT_STYLE[c]?.accent:undefined}
              onClick={()=> c==="all" ? onChange({...filters, cats:[]}) : toggle("cats", c)}>
              {c==="all"?"All":CAT_STYLE[c]?.label??c}
            </Chip>
          ))}
        </div>

        <Label>Chord type</Label>
        <div style={{display:"flex",gap:5,flexWrap:"wrap",marginBottom:18}}>
          <Chip active={chordNames.length===0} onClick={()=>onChange({...filters, chordNames:[]})}>All</Chip>
          {(availableChordNames||ALL_CHORD_NAMES).map(nm=>(
            <Chip key={nm} active={chordNames.includes(nm)} onClick={()=>toggle("chordNames", nm)}>{nm}</Chip>
          ))}
        </div>

        <Label>Contains note</Label>
        <div style={{display:"flex",gap:5,flexWrap:"wrap",marginBottom:20}}>
          <Chip active={notes.length===0} onClick={()=>onChange({...filters, notes:[]})}>All</Chip>
          {(noteList||NOTE_LIST).map(n=>(
            <Chip key={n} active={notes.includes(n)} color={NOTE_COLOR(n)}
              onClick={()=>toggle("notes", n)}>
              {n.replace("b","♭")}
            </Chip>
          ))}
        </div>

        <Label>Display</Label>
        <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",
          background:"rgba(255,255,255,0.03)",border:"1px solid rgba(255,255,255,0.07)",
          borderRadius:10,padding:"10px 14px",marginBottom:20,cursor:"pointer"}}
          onClick={()=>onChange({...filters, hideDuplicates:!filters.hideDuplicates})}>
          <div>
            <div style={{fontSize:12,color:"#c8b880",fontFamily:FONT,fontWeight:"500",marginBottom:2}}>
              Hide duplicates
            </div>
            <div style={{fontSize:10,color:"#6a5830",fontFamily:FONT}}>
              Show only the lowest-pitch voicing per chord
            </div>
          </div>
          {/* Toggle pill */}
          <div style={{
            width:44,height:24,borderRadius:12,flexShrink:0,marginLeft:12,
            background:filters.hideDuplicates?"rgba(200,184,120,0.30)":"rgba(255,255,255,0.07)",
            border:`1px solid ${filters.hideDuplicates?"rgba(205,163,83,0.60)":"rgba(255,255,255,0.10)"}`,
            position:"relative",transition:"all .2s",
          }}>
            <div style={{
              position:"absolute",top:3,
              left:filters.hideDuplicates?21:3,
              width:16,height:16,borderRadius:"50%",
              background:filters.hideDuplicates?"#cda353":"#4a3a18",
              transition:"left .2s",
              boxShadow:filters.hideDuplicates?"0 0 6px rgba(205,163,83,0.5)":"none",
            }}/>
          </div>
        </div>

        <button onClick={()=>onChange({noteCounts:[], cats:[], notes:[], chordNames:[], hideDuplicates:false})}
          style={{background:"rgba(150,50,50,0.15)",border:"1px solid rgba(150,50,50,0.30)",
            color:"#b06060",borderRadius:8,padding:"9px 20px",cursor:"pointer",fontSize:12,fontFamily:FONT,width:"100%"}}>
          Clear all filters
        </button>
        </div>{/* end centred content wrapper */}
      </div>
    </>
  );
}

// ═══════════════════════════════════════════════════════════════════
// CHORD CARD — merged voicings
// ═══════════════════════════════════════════════════════════════════
function ChordCard({chord, isSelected, isRelated, dimmed, onClick}) {
  const acc = CAT_STYLE[chord.cat]?.accent || "#c9a84c";
  const bg = isSelected
    ? "rgba(205,163,83,0.17)"
    : isRelated
      ? `${acc}18`
      : "rgba(255,255,255,0.03)";
  const border = isSelected ? "rgba(205,163,83,0.72)"
    : isRelated ? acc+"88"
    : "rgba(255,255,255,0.07)";

  return (
    <div onClick={onClick} style={{
      background:bg, border:`1px solid ${border}`,
      borderRadius:8, padding:"8px 11px", cursor:"pointer",
      transition:"all .15s",
      transform:isSelected?"scale(1.015)":"scale(1)",
      boxShadow:isSelected?"0 0 18px rgba(205,163,83,0.13)":isRelated?`0 0 8px ${acc}28`:"none",
      opacity:dimmed?0.35:1,
    }}>
      {/* Root + name */}
      <div style={{display:"flex",justifyContent:"space-between",alignItems:"flex-start",marginBottom:5}}>
        <div style={{display:"flex",alignItems:"baseline",gap:5}}>
          <span style={{color:isSelected?"#ecd898":acc,fontSize:13,fontFamily:FONT,fontWeight:"700",letterSpacing:.3}}>
            {chord.root.replace("b","♭")}
          </span>
          <span style={{color:isSelected?"#b8a060":"#806850",fontSize:10,fontFamily:FONT,fontWeight:"500"}}>
            {chord.name}
          </span>
        </div>
        <span style={{fontSize:8,color:acc+(isSelected?"cc":"66"),border:`1px solid ${acc}25`,
          borderRadius:3,padding:"1px 4px",flexShrink:0,fontFamily:FONT,letterSpacing:.5,marginLeft:4}}>
          {chord.noteCount}♩
        </span>
      </div>

      {/* Notes */}
      <div style={{display:"flex",gap:2,flexWrap:"wrap"}}>
        {chord.notes.map(n=>(
          <span key={n} style={{
            background:NOTE_COLOR(n)+"14",border:`1px solid ${NOTE_COLOR(n)}45`,
            color:NOTE_COLOR(n),borderRadius:3,padding:"0px 4px",
            fontSize:8.5,fontFamily:"monospace",lineHeight:"1.6",
          }}>{n.replace("b","♭")}</span>
        ))}
      </div>

    </div>
  );
}

// ── Storage helpers — localStorage works reliably in artifacts ──
const STORAGE_KEY = "hp_custom_pans_v2";
function savePans(pans) {
  try { localStorage.setItem(STORAGE_KEY, JSON.stringify(pans)); } catch(e) {}
}
function loadPans() {
  try {
    const v = localStorage.getItem(STORAGE_KEY);
    return v ? JSON.parse(v) : [];
  } catch(e) {}
  return [];
}

// ── Freq from midi ──────────────────────────────────────────────
function midiToFreq(midi) { return 440 * Math.pow(2, (midi - 69) / 12); }

// ── Standard presets ────────────────────────────────────────────
const STANDARD_PANS = [
  {
    id:"c_minor", name:"C Minor (9 notes)",
    notes:[
      {name:"C3",midi:48},{name:"C4",midi:60},{name:"D4",midi:62},
      {name:"Eb4",midi:63},{name:"F4",midi:65},{name:"G4",midi:67},
      {name:"Ab4",midi:68},{name:"C5",midi:72},{name:"D5",midi:74},
    ],
    positions:{
      "C3":"ding:0:upper","C5":"22.5:0:upper","G4":"67.5:0:upper","Eb4":"112.5:0:upper",
      "C4":"157.5:0:upper","D4":"202.5:0:upper","F4":"247.5:0:upper","Ab4":"292.5:0:upper","D5":"337.5:0:upper"
    },
    rings:{ upper:[{count:8,rotation:0}], bottom:[{count:6,rotation:0}] },
    sided:"single",
  },
];

// ── All 12 chromatic note letters ──────────────────────────────
const CHROMATIC = ["C","C#","Db","D","D#","Eb","E","F","F#","Gb","G","G#","Ab","A","A#","Bb","B"];
// Canonical per semitone (0-11): prefer sharps for natural notes, flats for black keys
const SEMITONE_NAMES = ["C","C#","D","Eb","E","F","F#","G","Ab","A","Bb","B"];

const MIDI_TO_NAME = {};
const ALL_NOTE_NAMES = []; // { name, midi, letter, octave }
for (let oct = 1; oct <= 7; oct++) {
  for (let semi = 0; semi < 12; semi++) {
    const midi = 12 + oct*12 + semi;
    const letter = SEMITONE_NAMES[semi];
    const name = letter + oct;
    MIDI_TO_NAME[midi] = name;
    ALL_NOTE_NAMES.push({ name, midi, letter, octave: oct,
      display: name.replace("b","♭").replace("#","♯") });
  }
}
const UNIQUE_LETTERS = SEMITONE_NAMES; // 12 unique pitch classes

// ── Note size types ─────────────────────────────────────────────
const NOTE_SIZES = {
  "big-ding":   { label:"Big Ding",    r:38, isDing:true,  fontSize:14, subFontSize:9.5 },
  "small-ding": { label:"Small Ding",  r:28, isDing:true,  fontSize:11, subFontSize:8   },
  "big":        { label:"Big",         r:26, isDing:false, fontSize:11, subFontSize:7.5 },
  "medium":     { label:"Medium",      r:22, isDing:false, fontSize:10, subFontSize:7   },
  "small":      { label:"Small",       r:16, isDing:false, fontSize:8,  subFontSize:6   },
};

// ── Ring system ─────────────────────────────────────────────────
const RING_RADII = [90, 62, 40]; // outer → inner

function getSnapAngles(count, rotation=0) {
  return Array.from({length:count}, (_,i) => ((360/count)*i + rotation + 360) % 360);
}
function snapToSlot(angle, slots) {
  return slots.reduce((best, a) => {
    const d = Math.abs(((angle-a+540)%360)-180);
    const bd= Math.abs(((angle-best+540)%360)-180);
    return d < bd ? a : best;
  }, slots[0]??0);
}

// ── Parse a position string "angle:ringIdx" or legacy "angle" ──
function parsePos(posStr) {
  if (!posStr) return { isDing:true };
  const parts = String(posStr).split(":");
  if (parts[0]==="ding"||parts[0]==="big-ding"||parts[0]==="small-ding")
    return { isDing:true };
  return { isDing:false, angle: parseFloat(parts[0])||0, ringIdx: parseInt(parts[1]||0) };
}

// ── Custom Dropdown component ───────────────────────────────────
function Dropdown({ value, onChange, options, placeholder="Select…", style:extraStyle={} }) {
  const [open, setOpen] = useState(false);
  const ref = useRef(null);
  const sel = options.find(o=>(o.value??o)===value);

  useEffect(()=>{
    const handler = e => { if(ref.current&&!ref.current.contains(e.target)) setOpen(false); };
    document.addEventListener("mousedown",handler);
    return ()=>document.removeEventListener("mousedown",handler);
  },[]);

  return (
    <div ref={ref} style={{position:"relative",...extraStyle}}>
      <button onClick={()=>setOpen(o=>!o)} style={{
        width:"100%",background:"rgba(255,255,255,0.06)",
        border:"1px solid rgba(255,255,255,0.14)",
        color:"#d4c8a8",borderRadius:7,padding:"6px 10px",
        cursor:"pointer",fontSize:11,fontFamily:FONT,
        display:"flex",justifyContent:"space-between",alignItems:"center",
        gap:6,textAlign:"left",
      }}>
        <span>{sel ? (sel.label??sel) : placeholder}</span>
        <span style={{opacity:.5,fontSize:9}}>{open?"▲":"▼"}</span>
      </button>
      {open&&(
        <div style={{
          position:"absolute",top:"calc(100% + 3px)",left:0,right:0,zIndex:500,
          background:"#1c1810",border:"1px solid rgba(205,163,83,0.30)",
          borderRadius:8,overflow:"auto",maxHeight:200,
          boxShadow:"0 8px 32px rgba(0,0,0,0.7)",
        }}>
          {options.map(o=>{
            const v=o.value??o; const l=o.label??o;
            const active=v===value;
            return (
              <button key={v} onClick={()=>{onChange(v);setOpen(false);}} style={{
                width:"100%",background:active?"rgba(205,163,83,0.15)":"transparent",
                border:"none",color:active?"#e8d098":"#b0a080",
                padding:"7px 10px",cursor:"pointer",fontSize:11,fontFamily:FONT,
                textAlign:"left",
                borderBottom:"1px solid rgba(255,255,255,0.04)",
              }}>{l}</button>
            );
          })}
        </div>
      )}
    </div>
  );
}


// ── PreviewPan is defined in the builder block below ─────────────

// ── Preview Pan SVG ───────────────────────────────────────────
// Reads positions in the new "angle:ringIdx:side" format.
// For each note, uses the rings array of the note's own side.
function PreviewPan({ notes, positions, ringsUpper, ringsBottom, activeNote, onNote, size=260, sid="pp" }) {
  const CX=150, CY=150;

  function notePos(n) {
    const posStr = positions?.[n.name];
    const p = parsePosV2(posStr, n.side||"upper");
    const sizeDef = NOTE_SIZES[n.size||"medium"]||NOTE_SIZES.medium;

    // Only at center if explicitly a ding position (no angle)
    if(p.isDing) return {x:CX,y:CY,r:sizeDef.r,isDing:true,sizeDef};

    // Use the rings of the note's side
    const sideRings = p.side==="bottom" ? (ringsBottom||[{count:6,rotation:0}]) : (ringsUpper||[{count:8,rotation:0}]);
    const safeRingsLen = Array.isArray(sideRings) ? sideRings.length : 1;
    const ri = Math.min(Math.max(p.ringIdx??0, 0), RING_RADII.length-1, safeRingsLen-1);
    const rr = RING_RADII[ri];
    const rad = ((p.angle-90)*Math.PI)/180;
    return {
      x:+(CX+rr*Math.cos(rad)).toFixed(2),
      y:+(CY+rr*Math.sin(rad)).toFixed(2),
      r:sizeDef.r, isDing:false, sizeDef
    };
  }

  const colFn = n => NOTE_COLOR(n.name);
  // Pick the ring guide circles based on which side the notes belong to
  const isBottomNotes = notes.length > 0 && notes.every(n=>(n.side||"upper")==="bottom");
  const ringListArr = Array.isArray(isBottomNotes ? ringsBottom : ringsUpper)
    ? (isBottomNotes ? ringsBottom : ringsUpper)
    : [{count:8,rotation:0}];

  return (
    <svg width="100%" height={typeof size==="number"?size:undefined} viewBox="0 0 300 300"
      style={{display:"block",maxWidth:typeof size==="number"?size:"100%",touchAction:"none",userSelect:"none",WebkitTapHighlightColor:"transparent"}}>
      <defs>
        <radialGradient id={`ppBg_${sid}`} cx="50%" cy="50%" r="55%">
          <stop offset="0%"  stopColor="#5c4e28"/>
          <stop offset="28%" stopColor="#3a3018"/>
          <stop offset="60%" stopColor="#1e1a0c"/>
          <stop offset="100%"stopColor="#080705"/>
        </radialGradient>
        <radialGradient id={`ppSh_${sid}`} cx="38%" cy="32%" r="48%">
          <stop offset="0%"  stopColor="rgba(255,230,140,0.20)"/>
          <stop offset="100%"stopColor="rgba(255,200,80,0.00)"/>
        </radialGradient>
        <filter id={`ppGl_${sid}`} x="-60%" y="-60%" width="220%" height="220%">
          <feGaussianBlur stdDeviation="5" result="b"/>
          <feMerge><feMergeNode in="b"/><feMergeNode in="SourceGraphic"/></feMerge>
        </filter>
      </defs>
      <circle cx={CX} cy={CY} r={146} fill="rgba(0,0,0,0.55)"/>
      <circle cx={CX} cy={CY} r={143} fill="none" stroke="rgba(160,120,40,0.30)" strokeWidth={1.5}/>
      <circle cx={CX} cy={CY} r={141} fill={`url(#ppBg_${sid})`} stroke="rgba(200,155,55,0.50)" strokeWidth={2}/>
      <circle cx={CX} cy={CY} r={138} fill="none" stroke="rgba(240,195,80,0.18)" strokeWidth={1}/>
      <circle cx={CX} cy={CY} r={141} fill={`url(#ppSh_${sid})`}/>
      {ringListArr.map((_,ri)=>(
        <circle key={ri} cx={CX} cy={CY} r={RING_RADII[ri]} fill="none"
          stroke="rgba(205,163,83,0.08)" strokeWidth={1} strokeDasharray="3 8"/>
      ))}
      {/* Bottom side hole */}
      {isBottomNotes&&(
        <circle cx={CX} cy={CY} r={32} fill="rgba(0,0,0,0.70)"
          stroke="rgba(140,110,45,0.30)" strokeWidth={1.5}/>
      )}

      {/* Spokes */}
      {notes.filter(n=>!notePos(n).isDing).map(n=>{
        const{x,y}=notePos(n); const lit=activeNote===n.name;
        return <line key={n.name} x1={CX} y1={CY} x2={x} y2={y}
          stroke={lit?colFn(n)+"55":"rgba(205,163,83,0.05)"} strokeWidth={lit?1.5:.8}/>;
      })}

      {/* Notes — ding last */}
      {[...notes.filter(n=>!notePos(n).isDing), ...notes.filter(n=>notePos(n).isDing)].map(n=>{
        const{x,y,r,isDing,sizeDef}=notePos(n);
        const lbl=n.name.replace("b","♭").replace(/\d/,"");
        const oct=n.name.match(/\d/)?.[0]||"";
        const lit=activeNote===n.name;
        const c=colFn(n);
        return (
          <g key={n.name} onClick={()=>onNote&&onNote(n)} style={{cursor:"pointer"}}>
            {lit&&<circle cx={x} cy={y} r={r+12} fill={c+"18"} filter={`url(#ppGl_${sid})`}/>}
            <circle cx={x} cy={y} r={r+2} fill="none"
              stroke={lit?c+"55":"rgba(180,140,55,0.12)"} strokeWidth={lit?1.5:1}/>
            <circle cx={x} cy={y} r={r}
              fill={lit?c+"35":isDing?"rgba(205,163,83,0.09)":"rgba(20,17,8,0.90)"}
              stroke={lit?c:isDing?"rgba(205,163,83,0.60)":"rgba(140,110,45,0.25)"}
              strokeWidth={lit?2.5:1.5}/>
            <circle cx={x} cy={y} r={Math.max(r-6,4)} fill="none"
              stroke={lit?c+"44":"rgba(205,163,83,0.05)"} strokeWidth={.8}/>
            <text x={x} y={isDing?y-(sizeDef.r>30?5:4):y+1}
              textAnchor="middle" dominantBaseline="middle"
              fontSize={sizeDef.fontSize} fontFamily={FONT} fontWeight="600"
              fill={lit?c:isDing?"#cda353":"#9a8a60"}
              style={{userSelect:"none",pointerEvents:"none"}}>{lbl}</text>
            {oct&&<text x={x} y={isDing?y+(sizeDef.r>30?9:7):y+r*0.55}
              textAnchor="middle" fontSize={sizeDef.subFontSize} fontFamily={FONT} fontWeight="600"
              fill={lit?c+(isDing?"cc":"99"):isDing?"#8a7040":"#7a6840"}
              style={{userSelect:"none",pointerEvents:"none"}}>{oct}</text>}
            {isDing&&<text x={x} y={y+(oct?r*0.75:r*0.5)}
              textAnchor="middle" fontSize={sizeDef.subFontSize-1} fontFamily={FONT} fontWeight="500"
              fill={lit?c+"cc":"#5a4a28"}
              style={{userSelect:"none",pointerEvents:"none"}}>ding</text>}
          </g>
        );
      })}
    </svg>
  );
}

// ── Builder Canvas ────────────────────────────────────────────
// rings = array of ringDefs for THIS side only
function BuilderCanvas({ notes, rings, onMove, onNoteClick, selectedNote, side="upper" }) {
  const svgRef    = useRef(null);
  const [dragging,setDragging] = useState(null);
  const [hover,   setHover]    = useState(null);
  const didMove   = useRef(false);
  const startPos  = useRef(null);       // for threshold detection
  const DRAG_THRESH = 8;                // px before drag starts
  const CX=150, CY=150;

  function svgPt(cx,cy) {
    const svg=svgRef.current; if(!svg) return{x:0,y:0};
    const r=svg.getBoundingClientRect();
    return{x:(cx-r.left)*(300/r.width),y:(cy-r.top)*(300/r.height)};
  }
  function toAngle(x,y){ return ((Math.atan2(y-CY,x-CX)*180/Math.PI)+90+360)%360; }
  function toRingIdx(x,y){
    const d=Math.sqrt((x-CX)**2+(y-CY)**2);
    if(d < RING_RADII[rings.length-1]*0.45) return -1; // center = ding
    let best=0,bd=Infinity;
    rings.forEach((_,i)=>{ const dd=Math.abs(d-RING_RADII[i]); if(dd<bd){bd=dd;best=i;} });
    return best;
  }
  function notePos(n) {
    const sizeDef = NOTE_SIZES[n.size||"medium"]||NOTE_SIZES.medium;
    // A note is at the center only if explicitly pos="ding" with no angle
    // Ding-size notes that have been dragged to a ring have an angle and ringIdx
    const isAtCenter = (n.pos==="ding"||n.ringIdx===-1||n.ringIdx==null) && n.angle==null;
    if(isAtCenter)
      return{x:CX,y:CY,r:sizeDef.r,isDing:true,sizeDef};
    // Notes with an angle are rendered on their ring, regardless of size
    const ri = Math.min(Math.max(n.ringIdx??0,0), RING_RADII.length-1, rings.length-1);
    const rr = RING_RADII[ri];
    const rad = (((n.angle??0)-90)*Math.PI)/180;
    return{x:+(CX+rr*Math.cos(rad)).toFixed(1),y:+(CY+rr*Math.sin(rad)).toFixed(1),r:sizeDef.r,isDing:false,sizeDef};
  }

  function onPD(e,name){
    const n=notes.find(x=>x.name===name); if(!n) return;
    e.stopPropagation();
    didMove.current=false;
    startPos.current={cx:e.clientX,cy:e.clientY};
    // Start lri at -1 only if the note is actually at center (no angle)
    const isAtCenter = (n.pos==="ding"||n.ringIdx===-1||n.ringIdx==null) && n.angle==null;
    const startLri = isAtCenter ? -1 : (n.ringIdx??0);
    setDragging({name,la:n.angle||0,lri:startLri,active:false});
    svgRef.current?.setPointerCapture(e.pointerId);
  }
  function onPM(e){
    if(!dragging) return;
    if(!dragging.active) {
      const dx=e.clientX-(startPos.current?.cx||0);
      const dy=e.clientY-(startPos.current?.cy||0);
      if(Math.sqrt(dx*dx+dy*dy) < DRAG_THRESH) return;
    }
    didMove.current=true;
    const{x,y}=svgPt(e.clientX,e.clientY);
    const ri=toRingIdx(x,y);
    // On bottom side, never show center position while dragging
    setDragging(d=>({...d,la:toAngle(x,y),lri: (side==="bottom"&&ri===-1)?0:ri,active:true}));
  }
  function onPU(e){
    if(!dragging) return;
    if(didMove.current) {
      const{x,y}=svgPt(e.clientX,e.clientY);
      const ri=toRingIdx(x,y);
      if(ri===-1) {
        // Center: only upper side can have a ding
        if(side!=="bottom") onMove(dragging.name,null,-1);
        // bottom: silently snap back
      } else {
        const ring=rings[ri]||rings[0];
        const slots=getSnapAngles(ring.count||8,ring.rotation||0);
        const snapped=snapToSlot(toAngle(x,y),slots);
        const halfSlot=360/ring.count/2;
        const conflict=notes.find(n=>
          n.name!==dragging.name&&(n.ringIdx??0)===ri&&
          !NOTE_SIZES[n.size||"medium"]?.isDing&&
          Math.abs((((n.angle||0)-snapped+540)%360)-180)<halfSlot
        );
        if(!conflict) onMove(dragging.name,snapped,ri);
      }
    }
    setDragging(null);
  }

  const renderNotes=notes.map(n=>{
    if(dragging?.active&&dragging.name===n.name) {
      return dragging.lri===-1
        ? {...n,pos:"ding",ringIdx:-1}
        : {...n,angle:dragging.la,ringIdx:dragging.lri,pos:"ring"};
    }
    return n;
  });

  const gid=`bc${side}`;

  return (
    <svg ref={svgRef} width="100%" viewBox="0 0 300 300"
      style={{display:"block",maxWidth:260,margin:"0 auto",touchAction:"none",userSelect:"none",WebkitUserSelect:"none",WebkitTapHighlightColor:"transparent"}}
      onPointerMove={onPM} onPointerUp={onPU}>
      <defs>
        <radialGradient id={`${gid}Bg`} cx="50%" cy="50%" r="55%">
          <stop offset="0%"  stopColor="#5c4e28"/>
          <stop offset="35%" stopColor="#3a3018"/>
          <stop offset="70%" stopColor="#1e1a0c"/>
          <stop offset="100%"stopColor="#080705"/>
        </radialGradient>
        <radialGradient id={`${gid}Sh`} cx="38%" cy="32%" r="48%">
          <stop offset="0%"  stopColor="rgba(255,230,140,0.18)"/>
          <stop offset="100%"stopColor="rgba(255,200,80,0.00)"/>
        </radialGradient>
        <filter id={`${gid}Gl`} x="-60%" y="-60%" width="220%" height="220%">
          <feGaussianBlur stdDeviation="4" result="b"/>
          <feMerge><feMergeNode in="b"/><feMergeNode in="SourceGraphic"/></feMerge>
        </filter>
      </defs>
      <circle cx={CX} cy={CY} r={146} fill="rgba(0,0,0,0.5)"/>
      <circle cx={CX} cy={CY} r={143} fill="none" stroke="rgba(160,120,40,0.25)" strokeWidth={1.5}/>
      <circle cx={CX} cy={CY} r={141} fill={`url(#${gid}Bg)`} stroke="rgba(200,155,55,0.42)" strokeWidth={2}/>
      <circle cx={CX} cy={CY} r={138} fill="none" stroke="rgba(240,195,80,0.12)" strokeWidth={1}/>
      <circle cx={CX} cy={CY} r={141} fill={`url(#${gid}Sh)`}/>

      {/* Ring guides */}
      {rings.map((ring,ri)=>{
        const rr=RING_RADII[ri];
        const slots=getSnapAngles(ring.count||8,ring.rotation||0);
        return (
          <g key={ri}>
            <circle cx={CX} cy={CY} r={rr} fill="none"
              stroke="rgba(205,163,83,0.10)" strokeWidth={1} strokeDasharray="3 8"/>
            {slots.map(a=>{
              const rad=((a-90)*Math.PI)/180;
              const sx=+(CX+rr*Math.cos(rad)).toFixed(1);
              const sy=+(CY+rr*Math.sin(rad)).toFixed(1);
              const taken=renderNotes.some(n=>
                (n.ringIdx??0)===ri&&!NOTE_SIZES[n.size||"medium"]?.isDing&&
                Math.abs(((n.angle||0)-a+360)%360)<(360/ring.count/2));
              return !taken&&<circle key={a} cx={sx} cy={sy} r={3}
                fill="none" stroke="rgba(205,163,83,0.22)" strokeWidth={1}/>;
            })}
          </g>
        );
      })}

      {/* Bottom side: draw a hole in the center */}
      {side==="bottom"&&(
        <>
          <circle cx={CX} cy={CY} r={36} fill="rgba(0,0,0,0.80)"
            stroke="rgba(140,110,45,0.35)" strokeWidth={1.5}/>
          <circle cx={CX} cy={CY} r={28} fill="none"
            stroke="rgba(100,80,30,0.20)" strokeWidth={1} strokeDasharray="2 4"/>
        </>
      )}

      {/* Notes */}
      {renderNotes.map(n=>{
        const{x,y,r,isDing,sizeDef}=notePos(n);
        const lbl=n.name.replace("b","♭").replace(/\d/,"");
        const oct=n.name.match(/\d/)?.[0]||"";
        const drag=dragging?.active&&dragging.name===n.name;
        const sel=selectedNote===n.name;
        const hov=hover===n.name;
        return (
          <g key={n.name}
            onPointerDown={e=>onPD(e,n.name)}
            onClick={()=>{ if(!didMove.current) onNoteClick&&onNoteClick(n); }}
            onMouseEnter={()=>setHover(n.name)}
            onMouseLeave={()=>setHover(null)}
            style={{cursor:drag?"grabbing":"grab"}}>
            {(sel||drag)&&<circle cx={x} cy={y} r={r+9} fill={sel?"rgba(205,163,83,0.10)":"none"}
              filter={`url(#${gid}Gl)`}/>}
            <circle cx={x} cy={y} r={r+2} fill="none"
              stroke={sel?"rgba(205,163,83,0.65)":drag||hov?"rgba(205,163,83,0.30)":"none"}
              strokeWidth={sel?1.5:1} strokeDasharray={sel?"none":"3 3"}/>
            <circle cx={x} cy={y} r={r}
              fill={drag?"rgba(205,163,83,0.28)":sel?"rgba(205,163,83,0.14)":"rgba(20,17,8,0.90)"}
              stroke={sel||drag?"rgba(205,163,83,0.85)":isDing?"rgba(205,163,83,0.55)":"rgba(140,110,45,0.28)"}
              strokeWidth={sel?2:1.5}/>
            <circle cx={x} cy={y} r={Math.max(r-6,4)} fill="none"
              stroke="rgba(205,163,83,0.06)" strokeWidth={.8}/>
            <text x={x} y={isDing?y-(sizeDef.r>30?5:4):y+1}
              textAnchor="middle" dominantBaseline="middle"
              fontSize={sizeDef.fontSize} fontFamily={FONT} fontWeight="600"
              fill={sel?"#e8c97a":isDing?"#cda353":"#9a8a60"}
              style={{userSelect:"none",pointerEvents:"none"}}>{lbl}</text>
            {oct&&<text x={x} y={isDing?y+(sizeDef.r>30?9:7):y+r*0.55}
              textAnchor="middle" fontSize={sizeDef.subFontSize} fontFamily={FONT} fontWeight="600"
              fill={sel?"#c8a050":isDing?"#7a6030":"#6a5838"}
              style={{userSelect:"none",pointerEvents:"none"}}>{oct}</text>}
            {isDing&&<text x={x} y={y+(oct?r*0.75:r*0.5)}
              textAnchor="middle" fontSize={sizeDef.subFontSize-1} fontFamily={FONT} fontWeight="500"
              fill={sel?"#b09040":"#5a4a28"}
              style={{userSelect:"none",pointerEvents:"none"}}>ding</text>}
          </g>
        );
      })}
    </svg>
  );
}

// ── Parse position string ─────────────────────────────────────
// Format: "angle:ringIdx:side" or "ding:0:upper" or legacy "angle:ringIdx"
function parsePosV2(posStr, fallbackSide="upper") {
  if(!posStr) return { isDing:true, side:fallbackSide };
  const parts = String(posStr).split(":");
  if(parts[0]==="ding"||parts[0]==="big-ding"||parts[0]==="small-ding")
    return { isDing:true, side:parts[2]||fallbackSide };
  return {
    isDing:  false,
    angle:   parseFloat(parts[0])||0,
    ringIdx: parseInt(parts[1]||0),
    side:    parts[2]||fallbackSide,
  };
}

// Build positions map from build notes
function buildPosMap(buildNotes) {
  const m={};
  buildNotes.forEach(n=>{
    const atCenter = (n.pos==="ding"||n.ringIdx==null||n.ringIdx===-1) && n.angle==null;
    if(atCenter)
      m[n.name] = `ding:0:${n.side||"upper"}`;
    else
      m[n.name] = `${n.angle??0}:${n.ringIdx??0}:${n.side||"upper"}`;
  });
  return m;
}

// ── Small handpan icon SVG ─────────────────────────────────────
