// ── Custom Slider ─────────────────────────────────────────────
function Slider({ min, max, step=1, value, onChange, label }) {
  const pct = max===min ? 0 : ((value-min)/(max-min))*100;
  return (
    <div style={{display:"flex",gap:8,alignItems:"center",flex:1}}>
      <div style={{flex:1,position:"relative",height:20,display:"flex",alignItems:"center"}}>
        <div style={{position:"absolute",left:0,right:0,height:3,background:"rgba(255,255,255,0.08)",borderRadius:2}}/>
        <div style={{position:"absolute",left:0,width:`${pct}%`,height:3,background:"rgba(205,163,83,0.60)",borderRadius:2}}/>
        <input type="range" min={min} max={max} step={step} value={value}
          onChange={e=>onChange(parseInt(e.target.value))}
          style={{position:"absolute",left:0,right:0,width:"100%",opacity:0,height:20,cursor:"pointer",margin:0,padding:0}}/>
        <div style={{
          position:"absolute",left:`calc(${pct}% - 7px)`,
          width:14,height:14,borderRadius:"50%",
          background:"#c9a84c",border:"2px solid #1a1408",
          pointerEvents:"none",boxShadow:"0 0 6px rgba(205,163,83,0.40)",
        }}/>
      </div>
      {label!==undefined&&<span style={{fontSize:9,color:"#6a5a30",minWidth:28,textAlign:"right",flexShrink:0}}>{label}</span>}
    </div>
  );
}

const EMPTY_BUILD = () => ({
  panName:"",
  editingId: null,
  sided:"single",
  activeSide:"upper",
  rings:{ upper:[{count:8,rotation:0}], bottom:[{count:6,rotation:0}] },
  buildNotes:[],
  selectedNote:null,
  showAddNote:false,
  editRingIdx:0,
  newLetter:"C",
  newOctave:4,
  newNoteSize:"big-ding",
  newNoteRing:0,
});

function HandpanBuilder({ open, onClose, onApply }) {
  const [tab, setTab]   = useState("preset");
  const [selectedPreset,setSelectedPreset] = useState(STANDARD_PANS[0].id);
  const [customPans,    setCustomPans]     = useState(()=>loadPans());
  const [selectedCustom,setSelectedCustom] = useState(null);
  const [build,   setBuild]   = useState(EMPTY_BUILD());
  const setB = (key,val) => setBuild(b=>({...b,[key]:val}));
  const [previewNote,setPreviewNote] = useState(null);
  const [visible,setVisible] = useState(false);
  const [animIn, setAnimIn]  = useState(false);
  const previewTimer = useRef(null);
  const [winW,setWinW] = useState(typeof window!=="undefined"?window.innerWidth:800);
  useEffect(()=>{ const h=()=>setWinW(window.innerWidth); window.addEventListener("resize",h); return()=>window.removeEventListener("resize",h); },[]);

  useEffect(()=>{
    if(open){ setCustomPans(loadPans()); setVisible(true); requestAnimationFrame(()=>requestAnimationFrame(()=>setAnimIn(true))); }
    else{ setAnimIn(false); const t=setTimeout(()=>setVisible(false),380); return()=>clearTimeout(t); }
  },[open]);
  if(!visible) return null;

  const {panName,editingId,sided,activeSide,rings,buildNotes,selectedNote,showAddNote,newLetter,newOctave,newNoteSize,newNoteRing}=build;
  const presetPan = STANDARD_PANS.find(p=>p.id===selectedPreset)||STANDARD_PANS[0];

  function previewTap(n) {
    if(!n?.midi) return;
    const ctx=getCtx(); synthNote(midiToFreq(n.midi),ctx.currentTime,ctx,0.44);
    setPreviewNote(n.name); clearTimeout(previewTimer.current);
    previewTimer.current=setTimeout(()=>setPreviewNote(null),600);
  }

  const sideRings     = rings[activeSide]||[{count:8,rotation:0}];
  const upperNotes    = buildNotes.filter(n=>n.side!=="bottom");
  const bottomNotes   = buildNotes.filter(n=>n.side==="bottom");
  const activeNotes   = activeSide==="bottom" ? bottomNotes : upperNotes;

  function moveNote(name,angle,ringIdx) {
    setB("buildNotes",buildNotes.map(n=>{
      if(n.name!==name) return n;
      if(ringIdx===-1) return{...n,pos:"ding",angle:null,ringIdx:-1};
      return{...n,pos:"ring",angle,ringIdx};
    }));
  }

  function addNote() {
    const midi=12+newOctave*12+SEMITONE_NAMES.indexOf(newLetter);
    if(midi<12||midi>120) return;
    const name=newLetter+newOctave;
    if(buildNotes.find(n=>n.name===name)){
      alert(`${name.replace("b","♭")} is already on this handpan.`); return;
    }
    const isDingSize=NOTE_SIZES[newNoteSize]?.isDing;
    const targetSide=sided==="double"?activeSide:"upper";
    // On bottom side, ding-size notes are allowed but go on a ring (no center)
    // On upper side, ding notes can go to center (angle=null) or ring
    const forceToRing = activeSide==="bottom" && isDingSize;
    let angle=null, ringIdx=null;
    if(!isDingSize || forceToRing) {
      const sRings=rings[targetSide]||[{count:8,rotation:0}];
      const ri=Math.min(newNoteRing, sRings.length-1);
      const ring=sRings[ri];
      const slots=getSnapAngles(ring.count||8,ring.rotation||0);
      const sideNotesOnRing=buildNotes.filter(n=>n.side===targetSide&&(n.ringIdx??0)===ri&&n.angle!=null);
      const usedAngles=sideNotesOnRing.map(n=>n.angle||0);
      const halfSlot=360/ring.count/2;
      const freeSlot=slots.find(a=>!usedAngles.some(ua=>Math.abs(((ua-a+540)%360)-180)<halfSlot));
      if(freeSlot===undefined){ alert(`Ring ${ri+1} is full. Remove a note or add another ring.`); return; }
      angle=freeSlot; ringIdx=ri;
    }
    // isDingSize and not forceToRing = upper ding → goes to center (angle=null, ringIdx=null)
    MIDI_TO_NAME[midi]=name;
    setBuild(b=>({...b,
      buildNotes:[...b.buildNotes,{name,midi,pos:(isDingSize&&!forceToRing)?"ding":"ring",angle,ringIdx,size:newNoteSize,side:targetSide}],
      selectedNote:name,showAddNote:false,
    }));
  }

  function updateNote(key,val){
    setB("buildNotes",buildNotes.map(n=>n.name===selectedNote?{...n,[key]:val}:n));
  }
  function removeNote(name){
    setBuild(b=>({...b,buildNotes:b.buildNotes.filter(n=>n.name!==name),selectedNote:b.selectedNote===name?null:b.selectedNote}));
  }
  const selNote=buildNotes.find(n=>n.name===selectedNote);

  function applyPreset(){
    const pan=STANDARD_PANS.find(p=>p.id===selectedPreset); if(!pan) return;
    const freq={}; pan.notes.forEach(n=>{freq[n.name]=pan.freq?.[n.name]||midiToFreq(n.midi);});
    onApply({notes:pan.notes,freq,positions:pan.positions,rings:pan.rings||{upper:[{count:8,rotation:0}],bottom:[{count:6,rotation:0}]},sided:pan.sided||"single",name:pan.name});
    onClose();
  }
  function applyCustom(){
    const pan=customPans.find(p=>p.id===selectedCustom); if(!pan) return;
    const freq={}; pan.notes.forEach(n=>{freq[n.name]=pan.freq?.[n.name]||midiToFreq(n.midi);});
    const panRings=pan.rings&&!Array.isArray(pan.rings)?pan.rings:{upper:Array.isArray(pan.rings)?pan.rings:[{count:8,rotation:0}],bottom:[{count:6,rotation:0}]};
    onApply({notes:pan.notes,freq,positions:pan.positions,rings:panRings,sided:pan.sided||"single",name:pan.name});
    onClose();
  }

  function editCustom(pan){
    // Reconstruct build notes from saved data
    const panRings=pan.rings&&!Array.isArray(pan.rings)?pan.rings:{upper:Array.isArray(pan.rings)?pan.rings:[{count:8,rotation:0}],bottom:[{count:6,rotation:0}]};
    const notes=pan.notes.map(n=>{
      const posStr=pan.positions?.[n.name];
      const p=parsePosV2(posStr,n.side||"upper");
      const size=n.size||(NOTE_SIZES[n.size||"medium"]?n.size:"medium");
      return{...n,size,pos:p.isDing?"ding":"ring",angle:p.isDing?null:p.angle,ringIdx:p.isDing?null:p.ringIdx,side:n.side||"upper"};
    });
    setBuild({...EMPTY_BUILD(),editingId:pan.id,panName:pan.name,sided:pan.sided||"single",rings:panRings,buildNotes:notes});
    setTab("build");
  }

  function saveAndApply(){
    const realNotes=buildNotes.filter(n=>n.name!=="_ph"&&n.name!=="placeholder");
    if(!panName.trim()||realNotes.length<1) return;
    const notesSorted=[...realNotes].sort((a,b)=>a.midi-b.midi);
    const freq={}; notesSorted.forEach(n=>{freq[n.name]=midiToFreq(n.midi);});
    const positions=buildPosMap(buildNotes);
    const existing=loadPans();
    let updated;
    if(editingId) {
      // Overwrite existing pan
      updated=existing.map(p=>p.id===editingId?{...p,name:panName.trim(),notes:notesSorted,freq,positions,rings,sided}:p);
    } else {
      // New pan
      const newPan={id:"custom_"+Date.now(),name:panName.trim(),notes:notesSorted,freq,positions,rings,sided};
      updated=[...existing,newPan];
    }
    savePans(updated); setCustomPans(updated);
    onApply({notes:notesSorted,freq,positions,rings,sided,name:panName.trim()});
    setBuild(EMPTY_BUILD()); onClose();
  }

  function saveAsNew(){
    const realNotes=buildNotes.filter(n=>n.name!=="_ph"&&n.name!=="placeholder");
    if(!panName.trim()||realNotes.length<1) return;
    const notesSorted=[...realNotes].sort((a,b)=>a.midi-b.midi);
    const freq={}; notesSorted.forEach(n=>{freq[n.name]=midiToFreq(n.midi);});
    const positions=buildPosMap(buildNotes);
    const newPan={id:"custom_"+Date.now(),name:panName.trim(),notes:notesSorted,freq,positions,rings,sided};
    const existing=loadPans();
    const updated=[...existing,newPan];
    savePans(updated); setCustomPans(updated);
    onApply({notes:notesSorted,freq,positions,rings,sided,name:panName.trim()});
    setBuild(EMPTY_BUILD()); onClose();
  }

  const BtnT=({active,onClick,children,color})=>(
    <button onClick={onClick} style={{
      background:active?(color?"rgba(100,200,130,0.18)":"rgba(205,163,83,0.18)"):"rgba(255,255,255,0.04)",
      border:`1px solid ${active?(color||"rgba(205,163,83,0.55)"):"rgba(255,255,255,0.08)"}`,
      color:active?(color||"#ddc870"):"#7a6a50",
      borderRadius:7,padding:"5px 12px",cursor:"pointer",fontSize:11,fontFamily:FONT,
      transition:"all .14s",whiteSpace:"nowrap",
    }}>{children}</button>
  );

  const letterOpts=SEMITONE_NAMES.map(l=>({value:l,label:l.replace("b","♭").replace("#","♯")}));
  const octaveOpts=[1,2,3,4,5,6,7].map(o=>({value:o,label:`Octave ${o}`}));
  const sizeOpts=Object.entries(NOTE_SIZES).map(([k,s])=>({value:k,label:s.label}));
  const ringOpts=(rings[activeSide]||[]).map((_,i)=>({value:i,label:`Ring ${i+1}`}));
  const isWide=winW>=560;
  const showDouble=sided==="double";

  return (
    <>
      <div onClick={onClose} style={{position:"fixed",inset:0,zIndex:300,background:"rgba(0,0,0,0.72)",backdropFilter:"blur(4px)",opacity:animIn?1:0,transition:"opacity .35s ease"}}/>
      <div style={{position:"fixed",inset:0,zIndex:301,display:"flex",alignItems:"center",justifyContent:"center",pointerEvents:"none",padding:"16px"}}>
        <div style={{background:"#141108",border:"1px solid rgba(205,163,83,0.22)",borderRadius:16,width:"100%",maxWidth:880,maxHeight:"92vh",overflowY:"auto",fontFamily:FONT,pointerEvents:"all",
          opacity:animIn?1:0,transform:animIn?"scale(1) translateY(0)":"scale(.96) translateY(16px)",
          transition:"opacity .35s ease, transform .35s cubic-bezier(.32,.72,0,1)",boxShadow:"0 24px 80px rgba(0,0,0,0.75)"}}>

          {/* Header */}
          <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",padding:"18px 22px 14px",borderBottom:"1px solid rgba(205,163,83,0.12)"}}>
            <div>
              <div style={{fontSize:17,color:"#e8d098",fontWeight:700}}>Handpan Workshop</div>
              <div style={{fontSize:9,color:"#5a4a28",letterSpacing:3,textTransform:"uppercase",marginTop:2}}>Select or build your instrument</div>
            </div>
            <button onClick={onClose} style={{background:"none",border:"none",color:"#6a5830",fontSize:20,cursor:"pointer",padding:"4px 8px",lineHeight:1}}>✕</button>
          </div>

          <div style={{padding:"16px 22px 28px"}}>
            {/* Tabs */}
            <div style={{display:"flex",gap:6,marginBottom:20,flexWrap:"wrap"}}>
              <BtnT active={tab==="preset"} onClick={()=>setTab("preset")}>🎵 Standard</BtnT>
              <BtnT active={tab==="custom"} color="#80d090"
                onClick={()=>{const f=loadPans();setCustomPans(f);setTab("custom");if(!selectedCustom&&f.length)setSelectedCustom(f[0].id);}}>
                📦 My Pans{customPans.length>0?` (${customPans.length})`:""}
              </BtnT>
              <BtnT active={tab==="build"} color="#a0b0e0" onClick={()=>setTab("build")}>⚒ Build</BtnT>
            </div>

            {/* ── PRESET ── */}
            {tab==="preset"&&(
              <div>
                <div style={{display:"flex",gap:6,flexWrap:"wrap",marginBottom:16}}>
                  {STANDARD_PANS.map(p=>(
                    <button key={p.id} onClick={()=>setSelectedPreset(p.id)} style={{
                      display:"flex",alignItems:"center",gap:5,
                      background:selectedPreset===p.id?"rgba(205,163,83,0.18)":"rgba(255,255,255,0.04)",
                      border:`1px solid ${selectedPreset===p.id?"rgba(205,163,83,0.55)":"rgba(255,255,255,0.08)"}`,
                      color:selectedPreset===p.id?"#ddc870":"#7a6a50",
                      borderRadius:7,padding:"5px 12px",cursor:"pointer",fontSize:11,fontFamily:FONT,
                    }}>
                      <PanIcon size={12} style={{color:"currentColor"}}/>
                      {p.sided==="double"&&<PanIcon size={12} style={{color:"currentColor"}}/>}
                      <span>{p.name}</span>
                    </button>
                  ))}
                </div>
                <div style={{display:"flex",justifyContent:"center",marginBottom:10}}>
                  <PreviewPan notes={presetPan.notes} positions={presetPan.positions}
                    ringsUpper={presetPan.rings?.upper||presetPan.rings||[{count:8,rotation:0}]}
                    ringsBottom={presetPan.rings?.bottom||[{count:6,rotation:0}]}
                    activeNote={previewNote} onNote={previewTap} size={260} sid="preset"/>
                </div>
                <div style={{fontSize:9,color:"#4a3a18",textAlign:"center",marginBottom:14,fontStyle:"italic"}}>Tap a note to preview its sound</div>
                <button onClick={applyPreset} style={{width:"100%",padding:"11px",background:"rgba(205,163,83,0.20)",border:"1px solid rgba(205,163,83,0.50)",color:"#e8d098",borderRadius:9,cursor:"pointer",fontSize:13,fontFamily:FONT,fontWeight:600}}>Use this handpan →</button>
              </div>
            )}

            {/* ── MY PANS ── */}
            {tab==="custom"&&(
              <div>
                {customPans.length===0?(
                  <div style={{textAlign:"center",padding:"32px 0",color:"#4a3a18",fontStyle:"italic",fontSize:13}}>No custom pans yet. Use the Build tab to create one.</div>
                ):(
                  <>
                    <div style={{display:"flex",gap:6,flexWrap:"wrap",marginBottom:18}}>
                      {customPans.map(p=>(
                        <div key={p.id} onClick={()=>setSelectedCustom(p.id)} style={{
                          display:"inline-flex",alignItems:"stretch",
                          border:`1px solid ${selectedCustom===p.id?"rgba(100,200,130,0.55)":"rgba(255,255,255,0.08)"}`,
                          borderRadius:8,overflow:"hidden",cursor:"pointer",
                          background:selectedCustom===p.id?"rgba(100,200,130,0.10)":"rgba(255,255,255,0.03)",
                          transition:"all .15s",
                        }}>
                          <div style={{display:"flex",alignItems:"center",gap:4,padding:"7px 10px",fontSize:12,
                            color:selectedCustom===p.id?"#80d090":"#9a8a60",fontFamily:FONT,fontWeight:500}}>
                            <PanIcon size={11}/>
                            {p.sided==="double"&&<PanIcon size={11}/>}
                            <span>{p.name}</span>
                          </div>
                          <button onClick={e=>{e.stopPropagation();editCustom(p);}} style={{
                            background:"rgba(160,160,220,0.10)",borderLeft:"1px solid rgba(255,255,255,0.07)",border:"none",
                            color:"#a0b0e0",cursor:"pointer",padding:"0 10px",fontSize:10,fontFamily:FONT,
                          }}>Edit</button>
                          <button onClick={e=>{
                            e.stopPropagation();
                            if(!window.confirm(`Delete "${p.name}"?`)) return;
                            const u=customPans.filter(x=>x.id!==p.id);
                            setCustomPans(u);savePans(u);
                            if(selectedCustom===p.id)setSelectedCustom(u[0]?.id||null);
                          }} style={{
                            background:"rgba(140,45,45,0.12)",borderLeft:"1px solid rgba(255,255,255,0.07)",border:"none",
                            color:"#a85858",cursor:"pointer",padding:"0 10px",fontSize:12,fontFamily:FONT,
                          }}>✕</button>
                        </div>
                      ))}
                    </div>
                    {selectedCustom&&(()=>{
                      const pan=customPans.find(p=>p.id===selectedCustom); if(!pan) return null;
                      const upper=pan.notes.filter(n=>n.side!=="bottom");
                      const bottom=pan.notes.filter(n=>n.side==="bottom");
                      const isDouble=pan.sided==="double"&&bottom.length>0;
                      const panRingsUpper = pan.rings?.upper
                        ? pan.rings.upper
                        : Array.isArray(pan.rings) ? pan.rings : [{count:8,rotation:0}];
                      const panRingsBottom = pan.rings?.bottom
                        ? pan.rings.bottom
                        : [{count:6,rotation:0}];
                      return (
                        <>
                          <div style={{display:"flex",gap:8,justifyContent:"center",marginBottom:12,alignItems:"flex-start",width:"100%",overflow:"hidden"}}>
                            <div style={{flex:"1 1 0",minWidth:0,textAlign:"center"}}>
                              {isDouble&&<div style={{fontSize:8,color:"#5a4a28",letterSpacing:2,textTransform:"uppercase",marginBottom:4}}>Upper</div>}
                              <PreviewPan notes={upper} positions={pan.positions||{}}
                                ringsUpper={panRingsUpper} ringsBottom={panRingsBottom}
                                activeNote={previewNote} onNote={previewTap} size="100%" sid="myU"/>
                            </div>
                            {isDouble&&(
                              <div style={{flex:"1 1 0",minWidth:0,textAlign:"center"}}>
                                <div style={{fontSize:8,color:"#5a4a28",letterSpacing:2,textTransform:"uppercase",marginBottom:4}}>Bottom</div>
                                <PreviewPan notes={bottom} positions={pan.positions||{}}
                                  ringsUpper={panRingsUpper} ringsBottom={panRingsBottom}
                                  activeNote={previewNote} onNote={previewTap} size="100%" sid="myB"/>
                              </div>
                            )}
                          </div>
                          <button onClick={applyCustom} style={{width:"100%",padding:"11px",background:"rgba(100,200,130,0.18)",border:"1px solid rgba(100,200,130,0.45)",color:"#80d090",borderRadius:9,cursor:"pointer",fontSize:13,fontFamily:FONT,fontWeight:600}}>Use this handpan →</button>
                        </>
                      );
                    })()}
                  </>
                )}
              </div>
            )}

            {/* ── BUILD ── */}
            {tab==="build"&&(
              <div style={{display:"flex",flexDirection:"column",gap:14}}>

                {/* Type + side toggle + Reset */}
                <div style={{display:"flex",gap:8,alignItems:"center",flexWrap:"wrap"}}>
                  <div style={{fontSize:9,color:"#6a5a30",letterSpacing:2,textTransform:"uppercase"}}>Type</div>
                  <BtnT active={sided==="single"} onClick={()=>setB("sided","single")}>○ Single</BtnT>
                  <BtnT active={sided==="double"} onClick={()=>setB("sided","double")}>◎ Double</BtnT>
                  {showDouble&&<>
                    <div style={{width:1,height:18,background:"rgba(255,255,255,0.10)",margin:"0 4px"}}/>
                    <BtnT active={activeSide==="upper"} onClick={()=>setB("activeSide","upper")}>Upper</BtnT>
                    <BtnT active={activeSide==="bottom"} onClick={()=>setB("activeSide","bottom")}>Bottom</BtnT>
                  </>}
                  <div style={{marginLeft:"auto"}}>
                    <button onClick={()=>{ if(window.confirm("Reset the build and start fresh?")) setBuild(EMPTY_BUILD()); }} style={{
                      background:"rgba(140,45,45,0.12)",border:"1px solid rgba(140,45,45,0.25)",
                      color:"#a85858",borderRadius:6,padding:"4px 10px",cursor:"pointer",
                      fontSize:10,fontFamily:FONT,
                    }}>↺ Reset</button>
                  </div>
                </div>

                {/* Rings editor — full width, one row, styled like edit-note panel */}
                <div style={{background:"rgba(205,163,83,0.05)",border:"1px solid rgba(205,163,83,0.18)",borderRadius:10,padding:"10px 14px"}}>
                  <div style={{display:"flex",alignItems:"center",gap:8,marginBottom:8,flexWrap:"wrap"}}>
                    <div style={{fontSize:9,color:"#c8a860",letterSpacing:2,textTransform:"uppercase",fontWeight:600}}>
                      Rings — {activeSide}
                    </div>
                    <Dropdown value={sideRings.length}
                      onChange={v=>{
                        const cur=rings[activeSide]||[{count:8,rotation:0}];
                        let next=[...cur];
                        while(next.length<v) next.push({count:6,rotation:0});
                        while(next.length>v) next.pop();
                        setB("rings",{...rings,[activeSide]:next});
                      }}
                      options={[1,2,3].map(n=>({value:n,label:`${n} ring${n>1?"s":""}`}))}
                      style={{width:100}}/>
                    <div style={{fontSize:9,color:"#5a4a28"}}>Editing ring:</div>
                    {sideRings.map((_,ri)=>(
                      <BtnT key={ri} active={build.editRingIdx===ri} onClick={()=>setB("editRingIdx",ri)}>Ring {ri+1}</BtnT>
                    ))}
                  </div>
                  {/* Ring settings for selected ring */}
                  {sideRings.length>0&&(()=>{
                    const ri=build.editRingIdx??0;
                    const ring=sideRings[ri]||sideRings[0];
                    if(!ring) return null;
                    const maxRot=Math.round(180/ring.count);
                    function updateRing(key,val){
                      const cur=rings[activeSide]||[];
                      const updated=cur.map((r,i)=>{
                        if(i!==ri) return r;
                        if(key==="rotation") {
                          const delta=val-(r.rotation||0);
                          // also rotate notes on this ring
                          setB("buildNotes",buildNotes.map(n=>{
                            if(n.side!==activeSide||(n.ringIdx??0)!==ri||n.angle==null) return n;
                            return{...n,angle:((n.angle+delta)+360)%360};
                          }));
                        }
                        if(key==="count") return{...r,[key]:val,rotation:0};
                        return{...r,[key]:val};
                      });
                      setB("rings",{...rings,[activeSide]:updated});
                    }
                    return (
                      <div style={{display:"flex",gap:12,alignItems:"center",flexWrap:"wrap"}}>
                        <div style={{display:"flex",gap:6,alignItems:"center"}}>
                          <span style={{fontSize:9,color:"#6a5a30"}}>Slots</span>
                          <Dropdown value={ring.count}
                            onChange={v=>updateRing("count",v)}
                            options={[4,5,6,7,8,9,10,11,12].map(n=>({value:n,label:`${n}`}))}
                            style={{width:72}}/>
                        </div>
                        <div style={{display:"flex",gap:6,alignItems:"center",flex:1,minWidth:150}}>
                          <span style={{fontSize:9,color:"#6a5a30",whiteSpace:"nowrap"}}>Rotate</span>
                          <Slider min={-maxRot} max={maxRot} value={ring.rotation||0}
                            onChange={v=>updateRing("rotation",v)} label={`${ring.rotation||0}°`}/>
                        </div>
                      </div>
                    );
                  })()}
                </div>

                {/* Canvas area */}
                <div>
                  <div style={{display:"flex",gap:12,justifyContent:"center",flexWrap:isWide?"nowrap":"wrap"}}>
                    <div style={{flex:"1 1 220px",maxWidth:270,display:showDouble&&!isWide&&activeSide==="bottom"?"none":"block"}}>
                      {showDouble&&<div style={{fontSize:9,color:"#6a5a30",textAlign:"center",letterSpacing:2,textTransform:"uppercase",marginBottom:4}}>Upper</div>}
                      <BuilderCanvas notes={upperNotes} rings={rings.upper||[{count:8,rotation:0}]}
                        onMove={moveNote}
                        onNoteClick={n=>{previewTap(n);setB("selectedNote",build.selectedNote===n.name?null:n.name);}}
                        selectedNote={selectedNote} side="upper"/>
                    </div>
                    {showDouble&&(
                      <div style={{flex:"1 1 220px",maxWidth:270,display:!isWide&&activeSide==="upper"?"none":"block"}}>
                        <div style={{fontSize:9,color:"#6a5a30",textAlign:"center",letterSpacing:2,textTransform:"uppercase",marginBottom:4}}>Bottom</div>
                        <BuilderCanvas notes={bottomNotes} rings={rings.bottom||[{count:6,rotation:0}]}
                          onMove={moveNote}
                          onNoteClick={n=>{previewTap(n);setB("selectedNote",build.selectedNote===n.name?null:n.name);}}
                          selectedNote={selectedNote} side="bottom"/>
                      </div>
                    )}
                  </div>
                  <div style={{fontSize:9,color:"#2e2610",textAlign:"center",marginTop:6,fontStyle:"italic"}}>Drag notes to snap · click to select &amp; edit</div>
                </div>

                {/* Unified note editor — shared fields for add-new and edit-selected */}
                <div style={{background:"rgba(205,163,83,0.06)",border:"1px solid rgba(205,163,83,0.18)",borderRadius:10,padding:"12px 14px"}}>
                  <div style={{display:"flex",gap:10,flexWrap:"wrap",marginBottom:10}}>
                    {/* Pitch */}
                    <div style={{flex:"1 1 170px"}}>
                      <div style={{fontSize:8,color:"#6a5a30",letterSpacing:2,textTransform:"uppercase",marginBottom:4}}>Pitch</div>
                      <div style={{display:"flex",gap:5,alignItems:"center"}}>
                        <Dropdown value={newLetter} onChange={l=>setB("newLetter",l)} options={letterOpts} style={{flex:1}}/>
                        <Dropdown value={newOctave} onChange={o=>setB("newOctave",o)} options={octaveOpts} style={{width:88}}/>
                        <button onClick={()=>{const midi=12+newOctave*12+SEMITONE_NAMES.indexOf(newLetter);const ctx=getCtx();synthNote(midiToFreq(midi),ctx.currentTime,ctx,.44);}}
                          style={{background:"rgba(205,163,83,0.12)",border:"1px solid rgba(205,163,83,0.30)",color:"#c9a84c",borderRadius:6,padding:"6px 10px",cursor:"pointer",fontSize:12}}>▶</button>
                      </div>
                    </div>
                    {/* Size */}
                    <div style={{flex:"1 1 130px"}}>
                      <div style={{fontSize:8,color:"#6a5a30",letterSpacing:2,textTransform:"uppercase",marginBottom:4}}>Size / Role</div>
                      <Dropdown value={newNoteSize} onChange={s=>setB("newNoteSize",s)} options={sizeOpts}/>
                    </div>
                    {/* Ring — only for non-ding or forced-to-ring */}
                    {(!NOTE_SIZES[newNoteSize]?.isDing || activeSide==="bottom") && (rings[activeSide]||[]).length>1&&(
                      <div style={{flex:"1 1 90px"}}>
                        <div style={{fontSize:8,color:"#6a5a30",letterSpacing:2,textTransform:"uppercase",marginBottom:4}}>Ring</div>
                        <Dropdown value={newNoteRing} onChange={r=>setB("newNoteRing",r)} options={ringOpts}/>
                      </div>
                    )}
                  </div>

                  {/* Action buttons */}
                  <div style={{display:"flex",gap:6,flexWrap:"wrap"}}>
                    <button onClick={addNote} style={{
                      flex:1,padding:"7px 12px",
                      background:"rgba(100,200,130,0.15)",border:"1px solid rgba(100,200,130,0.40)",
                      color:"#80d090",borderRadius:7,cursor:"pointer",fontSize:11,fontFamily:FONT,fontWeight:600,
                    }}>+ Add to {sided==="double"?activeSide:"upper"}</button>

                    {selNote&&(
                      <>
                        <button onClick={()=>{
                          // Update selected note pitch+size from the shared fields
                          const midi=12+newOctave*12+SEMITONE_NAMES.indexOf(newLetter);
                          const name=newLetter+newOctave;
                          const isDingSize=NOTE_SIZES[newNoteSize]?.isDing;
                          const forceToRing=selNote.side==="bottom"&&isDingSize;
                          // If switching to ding on upper, clear angle/ringIdx
                          let updates={size:newNoteSize};
                          if(isDingSize&&!forceToRing){
                            updates={...updates,pos:"ding",angle:null,ringIdx:null};
                          } else if(forceToRing&&selNote.angle==null){
                            // need to find a free slot
                            const sRings=rings[selNote.side||"upper"]||[{count:8,rotation:0}];
                            const ri=Math.min(newNoteRing,sRings.length-1);
                            const ring=sRings[ri];
                            const slots=getSnapAngles(ring.count||8,ring.rotation||0);
                            const used=buildNotes.filter(n=>n.name!==selNote.name&&n.side===selNote.side&&(n.ringIdx??0)===ri&&n.angle!=null).map(n=>n.angle||0);
                            const hs=360/ring.count/2;
                            const free=slots.find(a=>!used.some(ua=>Math.abs(((ua-a+540)%360)-180)<hs))||slots[0];
                            updates={...updates,pos:"ring",angle:free,ringIdx:ri};
                          }
                          if(name!==selNote.name) {
                            if(buildNotes.find(n=>n.name===name&&n.name!==selNote.name)){
                              alert(`${name.replace("b","♭")} is already on this handpan.`); return;
                            }
                            updates={...updates,name,midi};
                            MIDI_TO_NAME[midi]=name;
                          }
                          setBuild(b=>({...b,
                            buildNotes:b.buildNotes.map(n=>n.name===selectedNote?{...n,...updates}:n),
                            selectedNote:updates.name||selectedNote,
                          }));
                        }} style={{
                          flex:1,padding:"7px 12px",
                          background:"rgba(205,163,83,0.15)",border:"1px solid rgba(205,163,83,0.40)",
                          color:"#ddc870",borderRadius:7,cursor:"pointer",fontSize:11,fontFamily:FONT,fontWeight:600,
                        }}>↻ Update {selNote.name.replace("b","♭")}</button>

                        <button onClick={()=>removeNote(selectedNote)} style={{
                          padding:"7px 12px",
                          background:"rgba(140,45,45,0.12)",border:"1px solid rgba(140,45,45,0.28)",
                          color:"#a85858",borderRadius:7,cursor:"pointer",fontSize:11,fontFamily:FONT,
                        }}>Remove</button>
                      </>
                    )}
                  </div>
                </div>

                {/* Note list */}
                <div>
                  <div style={{fontSize:9,color:"#6a5a30",letterSpacing:2,textTransform:"uppercase",marginBottom:6}}>Notes ({buildNotes.length}) — click to select</div>
                  <div style={{display:"flex",gap:4,flexWrap:"wrap"}}>
                    {buildNotes.map(n=>(
                      <button key={n.name} onClick={()=>{
                        previewTap(n);
                        // Load note fields into the shared editor
                        const letter=n.name.replace(/\d/,"");
                        const octave=parseInt(n.name.match(/\d/)?.[0]||4);
                        setBuild(b=>({...b,
                          selectedNote:b.selectedNote===n.name?null:n.name,
                          newLetter:letter, newOctave:octave, newNoteSize:n.size||"medium",
                          newNoteRing:n.ringIdx??0,
                        }));
                      }} style={{
                        background:selectedNote===n.name?"rgba(205,163,83,0.20)":"rgba(255,255,255,0.04)",
                        border:`1px solid ${selectedNote===n.name?"rgba(205,163,83,0.55)":"rgba(255,255,255,0.08)"}`,
                        color:selectedNote===n.name?"#ddc870":"#8a7850",
                        borderRadius:6,padding:"3px 9px",cursor:"pointer",fontSize:10,fontFamily:FONT,
                      }}>
                        {n.name.replace("b","♭")}
                        <span style={{fontSize:8,color:"#5a4a28",marginLeft:3}}>{NOTE_SIZES[n.size||"medium"]?.label}</span>
                        {n.side==="bottom"&&<span style={{fontSize:7,color:"#4a5a28",marginLeft:2}}>(bot)</span>}
                      </button>
                    ))}
                    {buildNotes.length===0&&(
                      <span style={{fontSize:10,color:"#3a2c10",fontStyle:"italic"}}>No notes yet — use the fields above to add</span>
                    )}
                  </div>
                </div>

                {/* Save */}
                <div style={{borderTop:"1px solid rgba(255,255,255,0.06)",paddingTop:14}}>
                  <div style={{fontSize:9,color:"#6a5a30",letterSpacing:2,textTransform:"uppercase",marginBottom:8}}>
                    {editingId?"Save changes":"Save &amp; use"}
                  </div>
                  <div style={{display:"flex",gap:8,alignItems:"center",flexWrap:"wrap"}}>
                    <input value={panName} onChange={e=>setB("panName",e.target.value)} placeholder="Name your handpan…"
                      style={{flex:1,background:"rgba(255,255,255,0.05)",border:"1px solid rgba(255,255,255,0.10)",borderRadius:7,padding:"7px 12px",color:"#d4c8a8",fontSize:12,fontFamily:FONT,outline:"none"}}/>
                    <button onClick={saveAndApply} disabled={!panName.trim()||buildNotes.length<1} style={{
                      background:panName.trim()?"rgba(100,200,130,0.18)":"rgba(255,255,255,0.03)",
                      border:`1px solid ${panName.trim()?"rgba(100,200,130,0.45)":"rgba(255,255,255,0.07)"}`,
                      color:panName.trim()?"#80d090":"#3a3a30",
                      borderRadius:7,padding:"8px 14px",cursor:panName.trim()?"pointer":"default",
                      fontSize:12,fontFamily:FONT,fontWeight:600,whiteSpace:"nowrap",
                    }}>{editingId?"Save changes →":"Save & use →"}</button>
                    {editingId&&(
                      <button onClick={saveAsNew} disabled={!panName.trim()||buildNotes.length<1} style={{
                        background:"rgba(160,160,220,0.15)",border:"1px solid rgba(160,160,220,0.40)",
                        color:"#a0b0e0",borderRadius:7,padding:"8px 14px",cursor:"pointer",
                        fontSize:12,fontFamily:FONT,fontWeight:600,whiteSpace:"nowrap",
                      }}>Save as new →</button>
                    )}
                  </div>
                </div>

              </div>
            )}
          </div>
        </div>
      </div>
    </>
  );
}


export default function HandpanAtlas() {
  const [activeNotes,  setActiveNotes]  = useState([]); // lit on handpan (display)
  const [panNotes,     setPanNotes]     = useState([]); // drives list filter when panFiltering=true
  const [panFiltering, setPanFiltering] = useState(false);
  const [selectedKey,  setSelectedKey]  = useState(null);

  const [builderOpen, setBuilderOpen] = useState(false);

  // ── apply a new handpan from the builder ─────────────────────
  const [currentPan, setCurrentPan] = useState(()=>{
    const p=STANDARD_PANS[0];
    const freq={}; p.notes.forEach(n=>{freq[n.name]=midiToFreq(n.midi);});
    return {notes:p.notes,freq,positions:p.positions,rings:p.rings,sided:p.sided,name:p.name};
  });
  const applyHandpan = useCallback((pan) => {
    // Normalize rings to {upper, bottom} format
    let rings = pan.rings;
    if (!rings) rings = {upper:[{count:8,rotation:0}],bottom:[{count:6,rotation:0}]};
    else if (Array.isArray(rings)) rings = {upper:rings, bottom:[{count:6,rotation:0}]};
    setCurrentPan({
      notes: pan.notes,
      freq:  pan.freq,
      positions: pan.positions,
      rings,
      sided: pan.sided || "single",
      name:  pan.name,
    });
    setActiveNotes([]); setPanNotes([]); setPanFiltering(false); setSelectedKey(null);
  }, []);
  const [filters,    setFilters]    = useState({noteCounts:[3,4], cats:["Major","Minor","Diminished","Suspended"], notes:[], chordNames:[], hideDuplicates:true});
  const [search,     setSearch]     = useState("");
  const [filterOpen, setFilterOpen] = useState(false);
  const [strum,      setStrum]      = useState(true);

  const panMode = panFiltering && panNotes.length > 0;

  // ── chord detection — reactive to currentPan ─────────────────
  const panChords = useMemo(() => mergeChords(detectChords(currentPan.notes)), [currentPan]);
  const panChordNames = useMemo(() => [...new Set(panChords.map(c=>c.name))].sort(), [panChords]);
  const panAvailableCats = useMemo(() => CAT_ORDER.filter(cat=>panChords.some(c=>c.cat===cat)), [panChords]);

  // Cards that contain ALL pan-lit notes (related highlight)
  const relatedKeys = useMemo(() => {
    if (activeNotes.length === 0) return new Set();
    return new Set(
      panChords.filter(c => activeNotes.every(n => c.notes.includes(n))).map(c => c.key)
    );
  }, [activeNotes, panChords]);

  // ── note toggle ───────────────────────────────────────────────
  const handleNoteToggle = useCallback((noteName) => {
    setPanFiltering(true);
    setSelectedKey(null);
    // Always play the note — whether activating or deactivating
    // Use currentPan.freq first; fall back to computing from midi
    const freq = currentPan.freq?.[noteName] ||
      (() => { const n=currentPan.notes?.find(x=>x.name===noteName); return n?midiToFreq(n.midi):null; })();
    if (freq) { const ctx=getCtx(); synthNote(freq, ctx.currentTime, ctx, 0.44); }
    setActiveNotes(prev => {
      const was = prev.includes(noteName);
      const next = was ? prev.filter(n=>n!==noteName) : [...prev, noteName];
      setPanNotes(next);
      if (next.length === 0) setPanFiltering(false);
      return next;
    });
  }, [currentPan]);

  // ── chord card click: highlight + sound, never touch the list ──
  const handleChordClick = (chord) => {
    if (selectedKey === chord.key) {
      setSelectedKey(null);
      setActiveNotes(panMode ? panNotes : []);
      return;
    }
    setSelectedKey(chord.key);
    setActiveNotes(chord.notes); // light up handpan
    // panFiltering and panNotes untouched → list stays the same
    playChord(chord.notes, strum ? 0.13 : 0, currentPan.freq);
  };

  const showAll  = () => { setPanFiltering(false); setSelectedKey(null); };
  const clearAll = () => { setActiveNotes([]); setPanNotes([]); setPanFiltering(false); setSelectedKey(null); };
  const clearFilters = () => setFilters({noteCounts:[], cats:[], notes:[], chordNames:[], hideDuplicates:false});

  const filtered = useMemo(() => {
    let list = panChords;

    // Always apply the regular filters first
    const {noteCounts, cats, notes, chordNames} = filters;
    if (noteCounts.length > 0)   list = list.filter(c => noteCounts.includes(c.noteCount));
    if (cats.length > 0)         list = list.filter(c => cats.includes(c.cat));
    if (notes.length > 0)        list = list.filter(c => notes.some(n => c.notes.includes(n)));
    if (chordNames.length > 0)   list = list.filter(c => chordNames.includes(c.name));

    // Then additionally narrow by pan-tapped notes (intersection)
    if (panMode) {
      list = list.filter(c => panNotes.every(n => c.notes.includes(n)));
    }

    if (search.trim()) {
      const q = search.toLowerCase();
      list = list.filter(c => c.name.toLowerCase().includes(q) || c.root.toLowerCase().includes(q));
    }
    if (filters.hideDuplicates) {
      const groups = new Map();
      for (const c of list) {
        const groupKey = c.root + "|" + c.name;
        const avgMidi = c.notes.reduce((sum, n) => {
          const note = currentPan.notes.find(x => x.name === n);
          return sum + (note ? note.midi : 0);
        }, 0) / c.notes.length;
        if (!groups.has(groupKey) || avgMidi < groups.get(groupKey).avgMidi) {
          groups.set(groupKey, { chord: c, avgMidi });
        }
      }
      list = Array.from(groups.values()).map(g => g.chord);
    }
    return list;
  }, [panMode, panNotes, filters, search, panChords, currentPan]);

  const grouped = useMemo(() => {
    const g={};
    panAvailableCats.forEach(cat=>{g[cat]={};});
    filtered.forEach(c=>{
      if(!g[c.cat]) g[c.cat]={};
      if(!g[c.cat][c.name]) g[c.cat][c.name]=[];
      g[c.cat][c.name].push(c);
    });
    return g;
  }, [filtered]);

  const activeFilterCount = filters.noteCounts.length + filters.cats.length + filters.notes.length + filters.chordNames.length;

  return (
    <div style={{minHeight:"100vh",background:"#0a0906",color:"#d4c8a8",fontFamily:FONT,WebkitTextSizeAdjust:"100%"}}>

      {/* ── HEADER ── */}
      <div style={{
        background:"linear-gradient(180deg,#1a1508 0%,#0e0c07 100%)",
        borderBottom:"1px solid rgba(205,163,83,0.13)",
        padding:"20px 16px",textAlign:"center",
      }}>
        <h1 style={{
          fontSize:"clamp(28px,6vw,42px)",fontWeight:700,
          color:"#e8d4a0",margin:0,letterSpacing:-1,
          fontFamily:FONT,lineHeight:1.0,
          textShadow:"0 0 30px rgba(205,163,83,0.25)",
        }}>
          Handpan Hero
        </h1>
      </div>

      {/* ── STICKY HANDPAN ── */}
      <div style={{
        position:"sticky",top:0,zIndex:100,
        background:"rgba(8,7,4,0.97)",
        borderBottom:"1px solid rgba(205,163,83,0.15)",
        backdropFilter:"blur(12px)",WebkitBackdropFilter:"blur(12px)",
        padding:"10px 12px 10px",
        userSelect:"none",WebkitUserSelect:"none",
      }}>
        <div style={{maxWidth:600,margin:"0 auto",display:"flex",flexDirection:"column",alignItems:"center",gap:5}}>
          {/* Builder button row */}
          <div style={{width:"100%",display:"flex",justifyContent:"flex-start"}}>
            <button onClick={()=>setBuilderOpen(true)} title="Open Handpan Workshop"
              style={{
                background:"rgba(205,163,83,0.10)",border:"1px solid rgba(205,163,83,0.25)",
                borderRadius:7,padding:"4px 9px",cursor:"pointer",
                fontSize:10,color:"#c9a84c",fontFamily:FONT,
                display:"flex",alignItems:"center",gap:4,
              }}>
              <svg width="12" height="12" viewBox="0 0 14 14" fill="none">
                <circle cx="7" cy="7" r="6" stroke="currentColor" strokeWidth="1.2"/>
                <circle cx="7" cy="7" r="2.5" stroke="currentColor" strokeWidth="1"/>
                <circle cx="7" cy="2.5" r="1.2" fill="currentColor" opacity=".7"/>
                <circle cx="10.7" cy="4.8" r="1.2" fill="currentColor" opacity=".7"/>
                <circle cx="10.7" cy="9.2" r="1.2" fill="currentColor" opacity=".7"/>
                <circle cx="7" cy="11.5" r="1.2" fill="currentColor" opacity=".7"/>
                <circle cx="3.3" cy="9.2" r="1.2" fill="currentColor" opacity=".7"/>
                <circle cx="3.3" cy="4.8" r="1.2" fill="currentColor" opacity=".7"/>
              </svg>
              <span>{currentPan.name||"C Minor"}</span>
            </button>
          </div>
          {/* Diagrams row — side by side if double-sided, scale to fit */}
          <div style={{display:"flex",gap:4,justifyContent:"center",alignItems:"flex-start",width:"100%",maxWidth:"100%",overflow:"hidden"}}>
            <div style={{flex:"1 1 0",minWidth:0,maxWidth:260}}>
              {currentPan.sided==="double"&&<div style={{fontSize:7,color:"#5a4a28",textAlign:"center",letterSpacing:2,textTransform:"uppercase",marginBottom:2}}>Upper</div>}
              <HandpanDiagram uniqueId="upper"
                activeNotes={activeNotes} onNoteToggle={handleNoteToggle}
                notePositions={currentPan.positions}
                panNotes={(currentPan.notes||[]).filter(n=>n.side!=="bottom")}/>
            </div>
            {currentPan.sided==="double"&&(
              <div style={{flex:"1 1 0",minWidth:0,maxWidth:260}}>
                <div style={{fontSize:7,color:"#5a4a28",textAlign:"center",letterSpacing:2,textTransform:"uppercase",marginBottom:2}}>Bottom</div>
                <HandpanDiagram uniqueId="bottom"
                  activeNotes={activeNotes} onNoteToggle={handleNoteToggle}
                  notePositions={currentPan.positions}
                  panNotes={(currentPan.notes||[]).filter(n=>n.side==="bottom")}/>
              </div>
            )}
          </div>
          {/* Fixed-height info row — always reserves space so the div never resizes */}
          <div style={{width:"100%",maxWidth:440,textAlign:"center",height:38,display:"flex",flexDirection:"column",justifyContent:"center"}}>
            {activeNotes.length>0?(
              <>
                <div style={{display:"flex",gap:4,flexWrap:"wrap",justifyContent:"center",alignItems:"center",marginBottom:3}}>
                  <span style={{fontSize:8,color:"#5a4a28",letterSpacing:3,textTransform:"uppercase",fontFamily:FONT}}>
                    {panMode?"Playing":"Chord"}
                  </span>
                  {activeNotes.map(n=>(
                    <span key={n} onClick={()=>{ if(panMode) handleNoteToggle(n); else { setActiveNotes(prev=>prev.filter(x=>x!==n)); } }} style={{
                      background:NOTE_COLOR(n)+"20",border:`1px solid ${NOTE_COLOR(n)}66`,
                      color:NOTE_COLOR(n),borderRadius:4,padding:"1px 7px",
                      fontSize:10,fontFamily:"monospace",cursor:"pointer",
                    }}>{n.replace("b","♭")}{panMode?" ✕":""}</span>
                  ))}
                  <button onClick={clearAll} style={{
                    background:"rgba(140,45,45,0.15)",border:"1px solid rgba(140,45,45,0.30)",
                    color:"#a85858",borderRadius:5,padding:"2px 8px",cursor:"pointer",
                    fontSize:9,fontFamily:FONT,
                  }}>Clear</button>
                </div>
                <div style={{fontSize:9.5,color:"#5a4a28",fontStyle:"italic",fontFamily:FONT}}>
                  {panMode
                    ?(filtered.length>0?`${filtered.length} chord${filtered.length!==1?"s":""} found`:"No matching chords")
                    :`${relatedKeys.size} chord${relatedKeys.size!==1?"s":""} contain these notes`}
                </div>
              </>
            ):(
              <div style={{fontSize:9.5,color:"#2e2610",letterSpacing:.5,fontFamily:FONT}}>
                Tap notes to build a chord · or browse below
              </div>
            )}
          </div>
        </div>
      </div>

      {/* ── CONTENT WRAPPER ── */}
      <div style={{maxWidth:880,margin:"0 auto",padding:"0 12px"}}>

        {/* ── FILTER BAR ── */}
        <div style={{padding:"10px 0 0",display:"flex",gap:8,alignItems:"center",flexWrap:"wrap"}}>
          {/* Left group: filters + search + contextual buttons */}
          <button onClick={()=>setFilterOpen(true)} style={{
            display:"flex",alignItems:"center",gap:6,
            background:activeFilterCount>0?"rgba(205,163,83,0.16)":"rgba(255,255,255,0.05)",
            border:`1px solid ${activeFilterCount>0?"rgba(205,163,83,0.50)":"rgba(255,255,255,0.09)"}`,
            color:activeFilterCount>0?"#ddc870":"#7a6a50",
            borderRadius:8,padding:"7px 14px",cursor:"pointer",fontSize:12,fontFamily:FONT,transition:"all .15s",
          }}>
            <span>⚙ Filters</span>
            {activeFilterCount>0&&(
              <span style={{background:"rgba(205,163,83,0.32)",borderRadius:10,padding:"0 6px",fontSize:10,color:"#ddc870"}}>
                {activeFilterCount}
              </span>
            )}
          </button>

          <input value={search} onChange={e=>setSearch(e.target.value)} placeholder="Search chords…" style={{
            flex:1,minWidth:110,maxWidth:210,
            background:"rgba(255,255,255,0.04)",border:"1px solid rgba(255,255,255,0.09)",
            borderRadius:8,padding:"7px 12px",color:"#d4c8a8",fontSize:12,fontFamily:FONT,outline:"none",
          }}/>

          {panMode&&(
            <button onClick={showAll} style={{
              background:"rgba(205,163,83,0.12)",border:"1px solid rgba(205,163,83,0.35)",
              color:"#c9a84c",borderRadius:8,padding:"7px 13px",cursor:"pointer",fontSize:11,fontFamily:FONT,
            }}>Show all</button>
          )}
          {(activeFilterCount>0||search)&&!panMode&&(
            <button onClick={()=>{clearFilters();setSearch("");}} style={{
              background:"rgba(140,45,45,0.14)",border:"1px solid rgba(140,45,45,0.28)",
              color:"#a85858",borderRadius:8,padding:"6px 12px",cursor:"pointer",fontSize:11,fontFamily:FONT,
            }}>✕ Clear</button>
          )}

          {/* Spacer pushes right group to far right */}
          <span style={{flex:1}}/>

          {/* Right group: strum mode + play */}
          <div style={{display:"flex",gap:6,alignItems:"center",flexShrink:0}}>
            {/* Strum / Together toggle */}
            <button onClick={()=>setStrum(s=>!s)} style={{
              display:"flex",alignItems:"center",gap:5,
              background:strum?"rgba(205,163,83,0.14)":"rgba(255,255,255,0.04)",
              border:`1px solid ${strum?"rgba(205,163,83,0.40)":"rgba(255,255,255,0.09)"}`,
              color:strum?"#ddc870":"#7a6a50",
              borderRadius:8,padding:"6px 11px",cursor:"pointer",
              fontSize:11,fontFamily:FONT,transition:"all .15s",whiteSpace:"nowrap",
            }}>
              <span style={{fontSize:12,lineHeight:1}}>{strum?"〜":"‖"}</span>
              <span>{strum?"Strum":"Together"}</span>
            </button>

            {/* Play button — plays the active notes as a chord */}
            <button
              onClick={()=>{ if(activeNotes.length>0) playChord(activeNotes, strum?0.13:0, currentPan.freq); }}
              disabled={activeNotes.length===0}
              style={{
                display:"flex",alignItems:"center",gap:5,
                background:activeNotes.length>0?"rgba(100,180,120,0.18)":"rgba(255,255,255,0.03)",
                border:`1px solid ${activeNotes.length>0?"rgba(100,200,130,0.40)":"rgba(255,255,255,0.07)"}`,
                color:activeNotes.length>0?"#80d090":"#3a3a30",
                borderRadius:8,padding:"6px 13px",
                cursor:activeNotes.length>0?"pointer":"default",
                fontSize:12,fontFamily:FONT,transition:"all .15s",whiteSpace:"nowrap",
              }}>
              <span style={{fontSize:14,lineHeight:1}}>▶</span>
              <span style={{fontSize:11}}>Play</span>
            </button>
          </div>
        </div>

        {/* ── GROUPED CHORD LIST ── */}
        <div style={{padding:"10px 0 72px"}}>
          {panAvailableCats.map(cat=>{
            const nameMap=grouped[cat];
            if(!nameMap||Object.keys(nameMap).length===0) return null;
            const s=CAT_STYLE[cat];
            const sortedNames=Object.keys(nameMap).sort();
            return (
              <div key={cat} style={{marginBottom:28}}>
                <div style={{display:"flex",alignItems:"center",gap:10,marginBottom:12,
                  paddingBottom:7,borderBottom:`1px solid ${s.accent}22`}}>
                  <div style={{width:8,height:8,borderRadius:"50%",background:s.accent,flexShrink:0}}/>
                  <span style={{fontSize:11,color:s.accent,letterSpacing:3,textTransform:"uppercase",fontFamily:FONT,fontWeight:"600"}}>
                    {s.label}
                  </span>
                  <span style={{fontSize:10,color:s.accent+"55",fontFamily:FONT}}>
                    ({filtered.filter(c=>c.cat===cat).length})
                  </span>
                </div>

                {sortedNames.map(chordName=>{
                  const cards=nameMap[chordName];
                  return (
                    <div key={chordName} style={{marginBottom:12}}>
                      <div style={{fontSize:9.5,color:s.accent+"88",letterSpacing:2,textTransform:"uppercase",
                        fontFamily:FONT,fontWeight:"600",marginBottom:5,paddingLeft:2}}>{chordName}</div>
                      <div style={{display:"grid",gridTemplateColumns:"repeat(auto-fill,minmax(min(175px,100%),1fr))",gap:5}}>
                        {cards.map(chord=>{
                          const isSel=selectedKey===chord.key;
                          const isRel=!isSel&&relatedKeys.has(chord.key)&&activeNotes.length>0;
                          const isDimmed=activeNotes.length>0&&!panMode&&!isSel&&!isRel;
                          return (
                            <ChordCard key={chord.key} chord={chord}
                              isSelected={isSel} isRelated={isRel} dimmed={isDimmed}
                              onClick={()=>handleChordClick(chord)}/>
                          );
                        })}
                      </div>
                    </div>
                  );
                })}
              </div>
            );
          })}

          {filtered.length===0&&(
            <div style={{textAlign:"center",padding:"48px 20px",color:"#3a2c0e",fontSize:13,fontStyle:"italic",fontFamily:FONT}}>
              {panMode
                ?<><span>No chord found for this combination.</span><br/><span style={{fontSize:11}}>Try removing a note.</span></>
                :"No chords match these filters."}
            </div>
          )}
        </div>

      </div>{/* end content wrapper */}

      <FilterModal open={filterOpen} onClose={()=>setFilterOpen(false)} filters={filters} onChange={setFilters}
        availableCats={panAvailableCats} availableChordNames={panChordNames} noteList={currentPan.notes.map(n=>n.name)}/>
      <HandpanBuilder open={builderOpen} onClose={()=>setBuilderOpen(false)} onApply={applyHandpan}/>
    </div>
  );
}